I18N.register("de", {
  tips: {
    "Look at Rows and Columns Separately": ["Betrachten Sie Zeilen und Spalten getrennt", "Überprüfen Sie in einem Zahlenraster zunächst jede Zeile und dann jede Spalte. Oft folgt eine Richtung einer einfachen Regel: Zählen Sie von 2 bis 2 oder von 3 bis 3."],
    "Find the Rule Between Numbers": ["Finden Sie die Regel zwischen den Zahlen", "Fragen Sie sich: Was addiere, subtrahiere, multipliziere oder dividiere ich, um von einer Zahl zur nächsten zu gelangen? Probieren Sie jeden Vorgang aus, bis Sie einen gefunden haben, der für jeden Schritt funktioniert."],
    "Watch for Repeating Groups": ["Achten Sie auf sich wiederholende Gruppen", "Manchmal wiederholt sich eine Gruppe von Formen oder Symbolen endlos. Zählen Sie, wie viele Elemente die Gruppe hat, und sehen Sie dann, wo Sie sich im Zyklus befinden."],
    "Use Elimination": ["Eliminierung verwenden", "Wenn Sie sich nicht sicher sind, probieren Sie jede Antwort aus: Fügen Sie sie in das Muster ein und prüfen Sie, ob die Regel noch funktioniert. Eliminieren Sie alle Antworten, die das Muster durchbrechen."],
    "Find the Difference": ["Suchen Sie nach dem Unterschied", "Subtrahieren Sie jede Zahl von der davor. Ist die Differenz immer gleich, gilt die einfache Addition oder Subtraktion."],
    "Try Multiplying or Dividing": ["Versuchen Sie es mit Multiplizieren oder Dividieren", "Teilen Sie jede Zahl durch die vorherige Zahl. Wenn Sie jedes Mal das gleiche Ergebnis erhalten, wird die Zeichenfolge mit demselben Faktor multipliziert oder dividiert."],
    "Check for Two-Step Rules": ["Überprüfen Sie die Regeln in zwei Schritten", "Manchmal kombiniert die Regel zwei Operationen (z. B. zuerst +2, dann ×2). Schreiben Sie die Schritte auf den Entwurf und befolgen Sie sie der Reihe nach."],
    "Write It Down": ["Schreiben Sie es auf Papier", "Schreiben Sie die Zahlen und die Unterschiede oder Verhältnisse darunter. Auf dem Papier können Sie das Muster leichter erkennen als nur mit dem bloßen Auge."],
    "Read Every Word Carefully": ["Lesen Sie jedes Wort sorgfältig durch", "In der Logik kommt es auf Details an: Kleine Wörter wie „alle“, „einige“, „keine“, „sicherlich“ ändern die Bedeutung. Lesen Sie die Frage zweimal, bevor Sie eine Auswahl treffen."],
    "Draw a Picture or List": ["Zeichne oder erstelle eine Liste", "Skizzieren Sie die Personen, Tage oder Beziehungen, die das Problem betreffen. Eine einfache Liste oder Zeichnung zeigt deutlich, wer größer ist, wer zuerst kommt usw."],
    "Watch Out for Traps": ["Achten Sie auf Fallen", "Aus „Alle Hunde sind Tiere“ folgt nicht „Alle Tiere sind Hunde“. Drehen Sie die Regel nicht versehentlich um."],
    "Use 'If... Then...' Thinking": ["Denken Sie: „Wenn… dann…“", "Formulieren Sie die Aussagen um in „Wenn A, dann B“. Folgen Sie der Kette: Wenn A wahr ist, was muss als nächstes wahr sein?"],
    "Picture It in Your Mind": ["Stellen Sie es sich vor", "Versuchen Sie bei Formen und Würfeln, die Drehung oder Faltung zu „sehen“. Sie können den Entwurf kurz skizzieren."],
    "Know the Basics of Common Shapes": ["Kennt die Grundlagen gängiger Formen", "Der Würfel hat 6 Flächen, 12 Kanten und 8 Eckpunkte. Das dreieckige Prisma hat 5 Flächen. Wiederholen Sie diese Tatsachen und sie werden automatisch."],
    "Count What You Cannot See": ["Zählen und was nicht gesehen wird", "Bei geklebten Würfeln zählen verborgene Flächen, an denen sie sich berühren, nicht als sichtbare Flächen. Subtrahieren Sie die „geklebten“ Flächen von der Gesamtsumme."],
    "Use Nets to Understand Folding": ["Verwenden Sie die Entfaltung, um das Falten zu verstehen", "Die Entfaltung (das ausgeschnittene „Quadrat“, das sich zum Würfel faltet) zeigt, welche Flächen Nachbarn sind. Folgen Sie einem Gesicht und sehen Sie, bei welchem ​​es hängenbleibt."],
    "Read the Problem Twice": ["Lesen Sie die Aufgabe zweimal", "Viele Fallenprobleme basieren auf Eile. Die zweite Lesart fängt Phrasen wie „alle außer…“ oder „bleiben“ ein."],
    "Look for Trick Words": ["Suchen Sie nach Fallenschlüsselwörtern", "Ausdrücke wie „alle außer“, „verbleiben“, „insgesamt“, „jeder“ verändern die Berechnung. Unterstreiche sie."],
    "Break It Into Steps": ["In Schritte aufteilen", "Lösen Sie der Reihe nach: Zuerst, was Sie sicher wissen, dann addieren oder subtrahieren Sie je nach Problem. Versuchen Sie nicht alles auf einmal."],
    "Check Your Answer": ["Überprüfen Sie die Antwort", "Gehen Sie nach der Berechnung wieder der Frage nach: Ergibt die Antwort in der Geschichte einen Sinn? Wiederholen Sie die Berechnung bei Bedarf noch einmal."],
  },
  q: {
    "TPR811_1_01": ["Was kommt als nächstes? 2, 4, 6, 8, __", "Zählen Sie von 2 bis 2.", ["9", "10", "12", "11"], "Die Zeichenfolge erhöht sich bei jedem Schritt um 2: 2, 4, 6, 8, 10."],
    "TPR811_1_02": ["Was kommt als nächstes? 5, 10, 15, 20, __", "Zahlen sind Vielfache derselben Basiszahl.", ["22", "30", "25", "24"], "Die Zeichenfolge erhöht sich bei jedem Schritt um 5: 5, 10, 15, 20, 25."],
    "TPR811_1_03": ["Was kommt als nächstes? 3, 6, 9, 12, __", "Denken Sie an die Multiplikation mit 3 (das 3er-Brett).", ["14", "15", "16", "13"], "Die Zeichenfolge erhöht sich bei jedem Schritt um 3: 3, 6, 9, 12, 15."],
    "TPR811_1_04": ["Was kommt als nächstes? 10, 20, 30, 40, __", "Zählen Sie von 10 bis 10.", ["45", "55", "50", "60"], "Die Zeichenfolge erhöht sich bei jedem Schritt um 10: 10, 20, 30, 40, 50."],
    "TPR811_1_05": ["Was kommt als nächstes? 4, 8, 12, 16, __", "Sie sind Vielfache von 4.", ["18", "22", "24", "20"], "Die Zeichenfolge erhöht sich bei jedem Schritt um 4: 4, 8, 12, 16, 20."],
    "TPR811_1_06": ["Was ist die fehlende Zahl? 1, 3, 5, __, 9", "Es sind ungerade Zahlen.", ["6", "8", "7", "4"], "Es sind ungerade Zahlen, die um 2 steigen: 1, 3, 5, 7, 9."],
    "TPR811_1_07": ["Was kommt als nächstes? 2, 5, 8, 11, __", "Wie viel kommt jedes Mal zusammen?", ["12", "13", "15", "14"], "Jede Zahl ist 3 größer als die vorherige: 2, 5, 8, 11, 14."],
    "TPR811_1_08": ["Was ist die fehlende Zahl? 6, 12, __, 24, 30", "Zählen Sie von 6 bis 6.", ["15", "18", "20", "16"], "Die Saite erhöht sich von 6: 6, 12, 18, 24, 30."],
    "TPR811_1_09": ["Was kommt als nächstes? ○, □, ○, □, ○, __", "Die Formen wechseln sich ab.", ["○", "△", "□", "◇"], "Kreis und Quadrat wechseln sich ab. Nach dem Kreis kommt das Quadrat: ○, □, ○, □, ○, □."],
    "TPR811_1_10": ["Was kommt als nächstes? 7, 14, 21, 28, __", "Denken Sie an die Multiplikation mit 7 (das 7er-Brett).", ["30", "32", "36", "35"], "Die Zeichenfolge erhöht sich bei jedem Schritt um 7: 7, 14, 21, 28, 35."],
    "TPR811_1_11": ["Was ist die fehlende Zahl? 10, __, 30, 40, 50", "Zählen Sie von 10 bis 10.", ["15", "25", "20", "12"], "Die Zeichenfolge erhöht sich von 10: 10, 20, 30, 40, 50."],
    "TPR811_1_12": ["Was kommt als nächstes? 1, 4, 7, 10, __", "Wie viel kommt jedes Mal zusammen?", ["12", "14", "11", "13"], "Jede Zahl ist 3 größer als die vorherige: 1, 4, 7, 10, 13."],
    "TPR811_1_13": ["Was kommt als nächstes? A, B, A, B, A, __", "Die Buchstaben wechseln sich ab.", ["A", "c", "B", "d"], "Abwechselnd A und B: A, B, A, B, A, B."],
    "TPR811_1_14": ["Was kommt als nächstes? 8, 16, 24, 32, __", "Sie sind Vielfache von 8.", ["36", "38", "40", "42"], "Die Saite erhöht sich von 8: 8, 16, 24, 32, 40."],
    "TPR811_1_15": ["Was ist die fehlende Zahl? 5, 10, __, 20, 25", "Zählen Sie von 5 bis 5.", ["12", "14", "16", "15"], "Die Saite erhöht sich von 5: 5, 10, 15, 20, 25."],
    "TPR811_1_16": ["Was kommt als nächstes? 9, 18, 27, 36, __", "Sie sind Vielfache von 9.", ["45", "40", "42", "44"], "Die Saite erhöht sich von 9: 9, 18, 27, 36, 45."],
    "TPR811_1_17": ["Was kommt als nächstes? ★, ♥, ★, ♥, ★, __", "Zwei Symbole wechseln sich ab.", ["★", "♥", "♦", "○"], "Stern und Herz wechseln sich ab: ★, ♥, ★, ♥, ★, ♥."],
    "TPR811_1_18": ["Was ist die fehlende Zahl? 2, 4, __, 8, 10", "Zählen Sie von 2 bis 2.", ["5", "7", "6", "3"], "Die Saite erhöht sich von 2: 2, 4, 6, 8, 10."],
    "TPR811_1_19": ["Was kommt als nächstes? 11, 22, 33, 44, __", "Sie sind Vielfache von 11.", ["50", "55", "54", "56"], "Die Saite erhöht sich von 11: 11, 22, 33, 44, 55."],
    "TPR811_1_20": ["Was kommt als nächstes? 1, 2, 1, 2, 1, __", "Die Zahlen wiederholen sich immer gleich.", ["1", "3", "2", "0"], "Die Zahlen 1 und 2 wechseln sich ab: 1, 2, 1, 2, 1, 2."],
    "TPR811_2_01": ["In einem Raster lautet Zeile 1: 2, 4, 6, 8. Zeile 2 lautet: 3, 6, 9, 12. Zeile 3 lautet: 4, 8, __, 16. Wie lautet die fehlende Zahl?", "Jede Zeile enthält ein Vielfaches der ersten Zahl in dieser Zeile.", ["10", "11", "12", "14"], "Zeile 3 enthält Vielfache von 4: 4, 8, 12, 16."],
    "TPR811_2_02": ["Was kommt als nächstes? 1, 2, 4, 8, __", "Jede Zahl wird verdoppelt.", ["10", "12", "14", "16"], "Jede Zahl wird mit 2 multipliziert: 1, 2, 4, 8, 16."],
    "TPR811_2_03": ["Was kommt als nächstes? 3, 9, 27, __", "Jede Zahl wird mit demselben Faktor multipliziert.", ["36", "54", "81", "30"], "Jede Zahl wird mit 3 multipliziert: 3, 9, 27, 81."],
    "TPR811_2_04": ["Was kommt als nächstes in der Reihe? △, △, □, △, △, □, △, △, __", "Findet die Gruppe sich wiederholender Symbole.", ["△", "□", "○", "★"], "Das Muster wiederholt sich △, △, □ immer gleich. Position 9 ist □."],
    "TPR811_2_05": ["Raster: Zeile 1 ist 1, 2, 3. Zeile 2 ist 2, 4, 6. Zeile 3 ist 3, 6, __. Was ist die fehlende Zahl?", "Jede Zeile multipliziert die erste Zeile mit der Zeilennummer.", ["7", "8", "9", "10"], "Reihe 3 = oberste Reihe × 3. Also 3 × 3 = 9."],
    "TPR811_2_06": ["Was kommt als nächstes? 2, 6, 18, 54, __", "Multiplizieren Sie jedes Mal mit derselben Zahl.", ["108", "162", "72", "60"], "Jede Zahl wird mit 3 multipliziert: 2, 6, 18, 54, 162."],
    "TPR811_2_07": ["Was kommt als nächstes? 64, 32, 16, __", "Jede Zahl wird halbiert.", ["12", "10", "4", "8"], "Jede Zahl ist durch 2 teilbar: 64, 32, 16, 8."],
    "TPR811_2_08": ["Raster: Zeile 1 ist 1, 3, 5, 7. Zeile 2 ist 2, 6, 10, 14. Zeile 3 ist 3, 9, __, 21. Was ist die fehlende Zahl?", "Zeile 2 = Zeile 1 × 2. Wie viel kostet Zeile 3?", ["12", "15", "13", "17"], "Zeile 3 = Zeile 1 × 3. Also 5 × 3 = 15."],
    "TPR811_2_09": ["Was kommt als nächstes? 4, 8, 16, 32, __", "Jede Zahl wird verdoppelt.", ["48", "40", "64", "36"], "Jede Zahl wird mit 2 multipliziert: 4, 8, 16, 32, 64."],
    "TPR811_2_10": ["Was kommt als nächstes? ★, ♦, ♦, ★, ♦, ♦, ★, ♦, ♦, ★, __", "Finden Sie die Wiederholungsgruppe.", ["★", "♦", "○", "□"], "Das Muster wiederholt sich ★, ♦, ♦. Position 11 ist ♦."],
    "TPR811_2_11": ["Was kommt als nächstes? 5, 25, 125, __", "Multiplizieren Sie jedes Mal mit derselben Zahl.", ["150", "500", "250", "625"], "Jede Zahl wird mit 5 multipliziert: 5, 25, 125, 625."],
    "TPR811_2_12": ["Raster: Zeile 1 ist 2, 4, 6. Zeile 2 ist 3, 6, 9. Zeile 3 ist 5, 10, __. Was ist die fehlende Zahl?", "Jede Zeile enthält ein Vielfaches der ersten Zahl in dieser Zeile.", ["12", "14", "15", "20"], "Zeile 3 enthält Vielfache von 5: 5, 10, 15."],
    "TPR811_2_13": ["Was kommt als nächstes? 1, 4, 9, 16, __", "Es sind perfekte Quadrate: 1², 2², 3², 4²...", ["20", "25", "24", "36"], "Dies sind Quadratzahlen: 1, 4, 9, 16, 25 (was 1², 2², 3², 4², 5² hat)."],
    "TPR811_2_14": ["Was kommt als nächstes? A, A, B, A, A, B, A, A, B, __", "Finden Sie die sich wiederholende Dreiergruppe.", ["A", "B", "c", "d"], "Das Muster wiederholt sich A, A, B. Position 10 beginnt eine neue Gruppe, beginnend mit A."],
    "TPR811_2_15": ["Was kommt als nächstes? 1, 1, 2, 3, 5, 8, __", "Addieren Sie die beiden vorherigen Zahlen.", ["10", "11", "12", "13"], "Jede Zahl ist die Summe der beiden davor: 5 + 8 = 13. Dies ist die Fibonacci-Folge."],
    "TPR811_2_16": ["Raster: Zeile 1 ist 1, 2, 3, 4. Zeile 2 ist 2, 4, 6, 8. Zeile 3 ist 4, 8, __, 16. Was ist die fehlende Zahl?", "Reihe 3 = Reihe 1 × 4.", ["10", "12", "14", "9"], "Zeile 3 = Zeile 1 × 4. Also 3 × 4 = 12."],
    "TPR811_2_17": ["Was kommt als nächstes? 10, 100, 1000, __", "Bei jedem Schritt mit 10 multiplizieren.", ["1100", "2000", "10000", "5000"], "Jede Zahl wird mit 10 multipliziert: 10, 100, 1000, 10000."],
    "TPR811_2_18": ["Was kommt als nächstes? 1, 3, 6, 10, __", "Schauen Sie sich die Unterschiede an: +2, +3, +4 ...", ["13", "14", "15", "12"], "Die Differenz erhöht sich mit jedem Schritt um 1: +2, +3, +4, +5. Also 10 + 5 = 15. Das sind Dreieckszahlen."],
    "TPR811_2_19": ["Was kommt als nächstes? 1000, 500, 250, 125, __", "Jede Zahl wird halbiert.", ["62,5", "100", "75", "60"], "Jede Zahl ist durch 2 teilbar: 1000, 500, 250, 125, 62,5."],
    "TPR811_2_20": ["Was kommt als nächstes? 1, 8, 27, 64, __", "Das sind Würfelzahlen: 1³, 2³, 3³, 4³...", ["100", "81", "125", "216"], "Dies sind Würfelzahlen: 1³=1, 2³=8, 3³=27, 4³=64, 5³=125."],
    "TPR811_3_01": ["Was kommt als nächstes? 1, 3, 7, 15, __", "Versuchen Sie, mit 2 zu multiplizieren und dann 1 zu addieren.", ["29", "30", "31", "23"], "Regel: ×2, dann +1. 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_02": ["Was kommt als nächstes? 2, 5, 11, 23, __", "Versuchen Sie es mit x2 und dann mit +1.", ["35", "46", "47", "45"], "Regel: ×2, dann +1. 2→5, 5→11, 11→23, 23→47."],
    "TPR811_3_03": ["Was kommt als nächstes? ○, ○, □, △, ○, ○, □, △, ○, ○, __", "Finden Sie die Gruppe von 4 sich wiederholenden Symbolen.", ["○", "△", "□", "★"], "Das Muster wiederholt sich: ○, ○, □, △. Position 11 ist □."],
    "TPR811_3_04": ["Was kommt als nächstes? 1, 4, 13, 40, __", "Versuchen Sie es mit ×3 und dann mit +1.", ["80", "121", "120", "81"], "Regel: ×3, dann +1. 1→4, 4→13, 13→40, 40→121."],
    "TPR811_3_05": ["Raster: Zeile 1 ist 1, 4, 7. Zeile 2 ist 3, 10, 17. Zeile 3 ist 5, 16, __. Jede Zeile folgt der gleichen Additionsregel und Spalte 1 hat die Werte 1, 3, 5. Was ist die fehlende Zahl?", "Reihe 1 sammelt bei jedem Schritt 3 Maschen. In Reihe 2 werden bei jedem Schritt 7 gesammelt. Zeile 3 fügt hinzu ... Schauen Sie sich die ersten beiden Zahlen an.", ["27", "25", "21", "23"], "Zeile 3: 5, 16, 27. Die Differenz beträgt 11 in jedem Schritt (5+11=16, 16+11=27)."],
    "TPR811_3_06": ["Was kommt als nächstes? 2, 6, 14, 30, __", "Versuchen Sie es mit ×2 und dann mit +2.", ["58", "60", "62", "56"], "Regel: ×2, dann +2. 2→6, 6→14, 14→30, 30→62."],
    "TPR811_3_07": ["Was kommt als nächstes? 3, 7, 15, 31, __", "Versuchen Sie es mit x2 und dann mit +1.", ["47", "62", "63", "60"], "Regel: ×2, dann +1. 3→7, 7→15, 15→31, 31→63."],
    "TPR811_3_08": ["Was kommt als nächstes? 1, 2, 5, 10, 17, __", "Schauen Sie sich die Unterschiede zwischen den Zahlen an: 1, 3, 5, 7 ...", ["24", "25", "26", "22"], "Die Unterschiede sind ungerade Zahlen: +1, +3, +5, +7, +9. Also 17 + 9 = 26."],
    "TPR811_3_09": ["Raster: Zeile 1 ist 1, 4, 7. Zeile 2 ist 2, 8, 14. Zeile 3 ist 3, 12, __. Was ist die fehlende Zahl?", "Zeile 2 = Zeile 1 × 2. Zeile 3 = Zeile 1 × ?", ["18", "21", "15", "24"], "Zeile 3 = Zeile 1 × 3. Also 7 × 3 = 21."],
    "TPR811_3_10": ["Was kommt als nächstes? 0, 1, 3, 7, 15, __", "Versuchen Sie es mit x2 und dann mit +1.", ["31", "30", "23", "29"], "Regel: ×2, dann +1. 0→1, 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_11": ["Was kommt als nächstes? 2, 3, 5, 9, 17, __", "Schauen Sie sich die Unterschiede an: Sie verdoppeln sich bei jedem Schritt.", ["25", "33", "31", "34"], "Die Unterschiede werden verdoppelt: +1, +2, +4, +8, +16. Also 17 + 16 = 33."],
    "TPR811_3_12": ["Was kommt als nächstes? 1, 2, 6, 24, __", "1×2=2, 2×3=6, 6×4=24, 24×?...", ["48", "120", "96", "30"], "Mit steigenden Zahlen multiplizieren: ×2, ×3, ×4, ×5. Also 24 × 5 = 120."],
    "TPR811_3_13": ["Raster: Zeile 1 ist 2, 3, 4. Zeile 2 ist 5, 7, 9. Zeile 3 ist 11, 15, __. Die Regel zwischen den Zeilen lautet x2, dann +1. Was ist die fehlende Zahl?", "Wenden Sie die Regel auf jede Zahl in Zeile 2 an.", ["17", "18", "19", "21"], "9 × 2 + 1 = 19."],
    "TPR811_3_14": ["Was kommt als nächstes? 100, 98, 94, 86, 70, __", "Schauen Sie sich an, wie viel abgezogen wird: 2, 4, 8, 16 ...", ["54", "38", "50", "42"], "Skadeionen verdoppeln sich: −2, −4, −8, −16, −32. Also 70 − 32 = 38."],
    "TPR811_3_15": ["Was kommt als nächstes? 1, 4, 10, 22, __", "Versuchen Sie es mit ×2 und dann mit +2.", ["44", "46", "34", "40"], "Regel: ×2, dann +2. 1→4, 4→10, 10→22, 22→46."],
    "TPR811_3_16": ["Was kommt als nächstes? 5, 11, 23, 47, __", "Versuchen Sie es mit x2 und dann mit +1.", ["94", "95", "93", "96"], "Regel: ×2, dann +1. 5→11, 11→23, 23→47, 47→95."],
    "TPR811_3_17": ["Was kommt als nächstes? 1, 2, 4, 7, 11, 16, __", "Die Differenz erhöht sich bei jedem Schritt um 1: +1, +2, +3, +4, +5...", ["21", "22", "20", "23"], "Unterschiede: +1, +2, +3, +4, +5, +6. Also 16 + 6 = 22."],
    "TPR811_3_18": ["Rasterspalten: Spalte 1 ist 1, 2, 4. Spalte 2 ist 1, 3, 9. Spalte 3 ist 1, 4, __. Was ist die fehlende Zahl?", "Spalte 1 enthält Potenzen von 2. Spalte 2 enthält Potenzen von 3. Spalte 3 enthält Potenzen von ?", ["8", "12", "16", "20"], "Spalte 3 enthält Potenzen von 4: 4⁰=1, 4¹=4, 4²=16."],
    "TPR811_3_19": ["Was kommt als nächstes? 2, 5, 14, 41, __", "Versuchen Sie es mit ×3 und dann mit −1.", ["82", "122", "123", "124"], "Regel: ×3, dann −1. 2→5, 5→14, 14→41, 41→122."],
    "TPR811_3_20": ["Was kommt als nächstes? 1, 3, 9, 27, 81, __", "Jede Zahl wird mit 3 multipliziert.", ["162", "243", "108", "100"], "Jede Zahl ist ×3: 1, 3, 9, 27, 81, 243."],
    "TNR811_1_01": ["Wie viel ist 3 × 4?", "Denken Sie an 3 Gruppen zu je 4 Personen.", ["7", "10", "12", "14"], "3 × 4 = 12."],
    "TNR811_1_02": ["Wie viel ist 5 × 6?", "Denken Sie an 5 Gruppen zu je 6 Personen.", ["25", "30", "35", "36"], "5 × 6 = 30."],
    "TNR811_1_03": ["Was kommt als nächstes? 5, 10, 15, 20, __", "Zählen Sie von 5 bis 5.", ["24", "25", "30", "22"], "Zählen in 5-Sekunden-Schritten: 5, 10, 15, 20, 25."],
    "TNR811_1_04": ["Was ist das Doppelte von 8?", "Doppelt bedeutet ×2.", ["14", "16", "18", "10"], "Doppelt 8 = 8 × 2 = 16."],
    "TNR811_1_05": ["Wie viel ist 4 × 7?", "Denken Sie an 4 Gruppen zu je 7 Personen.", ["24", "21", "28", "32"], "4 × 7 = 28."],
    "TNR811_1_06": ["Was kommt als nächstes? 3, 6, 9, 12, __", "Zählen Sie von 3 bis 3.", ["13", "14", "15", "16"], "Counting by 3s: 3, 6, 9, 12, 15."],
    "TNR811_1_07": ["Was ist das Doppelte von 15?", "Double bedeutet, mit 2 multiplizieren.", ["25", "28", "30", "35"], "Doppelt 15 = 15 × 2 = 30."],
    "TNR811_1_08": ["Wie viel ist 5 × 8?", "Denken Sie an 5 Gruppen zu je 8 Personen.", ["35", "45", "40", "48"], "5 × 8 = 40."],
    "TNR811_1_09": ["Anzahl der Vieren: 4, 8, 12, __, 20. Wie viel fehlt?", "Wie viel ist 12 + 4?", ["14", "16", "15", "18"], "Zählen in 4er-Schritten: 4, 8, 12, 16, 20."],
    "TNR811_1_10": ["Wie viel ist 3 × 9?", "Denken Sie an 3 Gruppen zu je 9 Personen.", ["24", "27", "21", "29"], "3 × 9 = 27."],
    "TNR811_1_11": ["Was ist das Doppelte von 25?", "Doppelt bedeutet ×2.", ["45", "50", "55", "40"], "Doppelt 25 = 25 × 2 = 50."],
    "TNR811_1_12": ["Wie viel ist 4 × 8?", "Denken Sie an 4 Gruppen zu je 8 Personen.", ["28", "30", "32", "36"], "4 × 8 = 32."],
    "TNR811_1_13": ["Zahl aus 6ern: 6, 12, 18, __, 30. Wie viel fehlt?", "Was ist 18 + 6?", ["22", "26", "24", "20"], "Zählen in 6er-Schritten: 6, 12, 18, 24, 30."],
    "TNR811_1_14": ["Wie viel ist 5 × 9?", "Denken Sie an 5 Gruppen zu je 9 Personen.", ["40", "50", "45", "54"], "5 × 9 = 45."],
    "TNR811_1_15": ["Was ist das Doppelte von 12?", "Doppelt bedeutet ×2.", ["22", "24", "20", "26"], "Doppelt 12 = 12 × 2 = 24."],
    "TNR811_1_16": ["Wie viel ist 3 × 7?", "Denken Sie an 3 Gruppen zu je 7 Personen.", ["18", "24", "21", "28"], "3 × 7 = 21."],
    "TNR811_1_17": ["Zahl aus 3ern: 3, 6, 9, 12, 15, __. Was kommt als nächstes?", "Sammle bei jedem Schritt 3.", ["16", "17", "18", "19"], "Zählen in Dreierschritten: 3, 6, 9, 12, 15, 18."],
    "TNR811_1_18": ["Wie viel ist 4 × 9?", "Denken Sie an 4 Gruppen zu je 9 Personen.", ["32", "36", "40", "27"], "4 × 9 = 36."],
    "TNR811_1_19": ["Was ist das Doppelte von 35?", "Doppelt bedeutet ×2.", ["60", "65", "70", "75"], "Doppelt 35 = 35 × 2 = 70."],
    "TNR811_1_20": ["Wie viel ist 5 × 7?", "Denken Sie an 5 Gruppen zu je 7 Personen.", ["30", "35", "40", "42"], "5 × 7 = 35."],
    "TNR811_2_01": ["Was ist die Hälfte von 48?", "Die Hälfte bedeutet ÷2.", ["20", "22", "24", "28"], "Die Hälfte von 48 = 48 ÷ 2 = 24."],
    "TNR811_2_02": ["Was ist das Tripel von 9?", "Dreifach bedeutet ×3.", ["18", "27", "24", "21"], "Tripel 9 = 9 × 3 = 27."],
    "TNR811_2_03": ["Zeichenfolge: 2, 4, 3, 6, 5, 10, 9, __. Die Regel wechselt: verdoppeln, dann 1 subtrahieren. Wie geht es weiter?", "9 kommt nach einem Subtraktionsschritt. Welche Operation steht als nächstes an?", ["10", "18", "8", "12"], "Das Muster wechselt zwischen ×2 und −1. Nach 9 verdoppeln wir: 9 × 2 = 18."],
    "TNR811_2_04": ["Was ist die Hälfte von 64?", "Die Hälfte bedeutet ÷2.", ["30", "34", "32", "36"], "Die Hälfte von 64 = 64 ÷ 2 = 32."],
    "TNR811_2_05": ["Was ist das Tripel von 12?", "Dreifach bedeutet ×3.", ["24", "30", "36", "48"], "Dreifach 12 = 12 × 3 = 36."],
    "TNR811_2_06": ["Zeichenfolge: 1, 3, 2, 6, 5, 15, 14, __. Die Regel wechselt: ×3, dann −1. Was kommt als nächstes?", "14 kommt, nachdem Sie 1 subtrahiert haben. Welche Operation kommt als nächstes?", ["13", "28", "42", "15"], "Wechsel: ×3 und −1. Nach 14 multiplizieren wir: 14 × 3 = 42."],
    "TNR811_2_07": ["Wie viel ist die Hälfte von 100?", "Die Hälfte bedeutet ÷2.", ["40", "50", "55", "45"], "Die Hälfte von 100 = 100 ÷ 2 = 50."],
    "TNR811_2_08": ["Was ist das Tripel von 15?", "Dreifach bedeutet ×3.", ["30", "40", "45", "60"], "Dreifach 15 = 15 × 3 = 45."],
    "TNR811_2_09": ["Was kommt als nächstes? 80, 40, 20, __", "Jede Zahl wird halbiert.", ["15", "10", "5", "12"], "Jede Zahl ist durch 2 teilbar: 80, 40, 20, 10."],
    "TNR811_2_10": ["Was ist die Hälfte von 36?", "Die Hälfte bedeutet ÷2.", ["16", "18", "20", "14"], "Die Hälfte von 36 = 36 ÷ 2 = 18."],
    "TNR811_2_11": ["Was ist das Tripel von 20?", "Dreifach bedeutet ×3.", ["40", "50", "60", "80"], "Dreifach 20 = 20 × 3 = 60."],
    "TNR811_2_12": ["Zeichenfolge: 1, 2, 4, 5, 10, 11, 22, __. Die Regel wechselt: +1, dann ×2. Was kommt als nächstes?", "22 kommt nach der Verdoppelung. Welche Operation steht als nächstes an?", ["23", "24", "44", "32"], "Wechsel: +1 und ×2. Nach 22 addieren wir 1: 22 + 1 = 23."],
    "TNR811_2_13": ["Was ist die Hälfte von 56?", "Die Hälfte bedeutet ÷2.", ["24", "26", "28", "30"], "Die Hälfte von 56 = 56 ÷ 2 = 28."],
    "TNR811_2_14": ["Was ist das Tripel von 8?", "Dreifach bedeutet ×3.", ["16", "20", "24", "28"], "Dreifach 8 = 8 × 3 = 24."],
    "TNR811_2_15": ["Was kommt als nächstes? 96, 48, 24, 12, __", "Jede Zahl wird halbiert.", ["8", "6", "10", "4"], "Jede Zahl ist durch 2 teilbar: 96, 48, 24, 12, 6."],
    "TNR811_2_16": ["Was ist die Hälfte von 72?", "Die Hälfte bedeutet ÷2.", ["32", "34", "36", "38"], "Die Hälfte von 72 = 72 ÷ 2 = 36."],
    "TNR811_2_17": ["Was ist das Tripel von 25?", "Dreifach bedeutet ×3.", ["50", "65", "75", "100"], "Dreifach 25 = 25 × 3 = 75."],
    "TNR811_2_18": ["Zeichenfolge: 5, 15, 10, 30, 25, 75, 70, __. Die Regel wechselt: ×3, dann −5. Was kommt als nächstes?", "70 kommt, nachdem Sie 5 subtrahiert haben. Welche Operation folgt als nächstes?", ["65", "140", "210", "105"], "Wechsel: ×3 und −5. Nach 70 multiplizieren wir: 70 × 3 = 210."],
    "TNR811_2_19": ["Was ist die Hälfte von 84?", "Die Hälfte bedeutet ÷2.", ["38", "40", "42", "44"], "Die Hälfte von 84 = 84 ÷ 2 = 42."],
    "TNR811_2_20": ["Was ist das Tripel von 30?", "Dreifach bedeutet ×3.", ["60", "90", "100", "120"], "Dreifach 30 = 30 × 3 = 90."],
    "TNR811_3_01": ["Was kommt als nächstes? 1, 3, 7, 15, 31, __", "Versuchen Sie es mit x2 und dann mit +1.", ["47", "62", "63", "60"], "Regel: ×2, dann +1. 1→3, 3→7, 7→15, 15→31, 31→63."],
    "TNR811_3_02": ["Was kommt als nächstes? 2, 6, 18, 54, __", "Jede Zahl ist ×3.", ["108", "162", "72", "60"], "Jede Zahl wird mit 3 multipliziert: 2, 6, 18, 54, 162."],
    "TNR811_3_03": ["Was kommt als nächstes? 100, 97, 91, 82, 70, __", "Schauen Sie sich die Unterschiede an: −3, −6, −9, −12...", ["58", "55", "52", "60"], "Die Unterschiede erhöhen sich um 3: −3, −6, −9, −12, −15. Also 70 − 15 = 55."],
    "TNR811_3_04": ["Was kommt als nächstes? 3, 4, 6, 10, 18, __", "Schauen Sie sich die Unterschiede an: 1, 2, 4, 8 ... sie verdoppeln sich.", ["26", "34", "28", "36"], "Die Unterschiede werden verdoppelt: +1, +2, +4, +8, +16. Also 18 + 16 = 34."],
    "TNR811_3_05": ["Was kommt als nächstes? 2, 5, 11, 23, 47, __", "Versuchen Sie es mit x2 und dann mit +1.", ["94", "95", "93", "96"], "Regel: ×2, dann +1. 2→5, 5→11, 11→23, 23→47, 47→95."],
    "TNR811_3_06": ["Was kommt als nächstes? 256, 128, 64, 32, __", "Jede Zahl wird halbiert.", ["24", "16", "8", "20"], "Jede Zahl ist durch 2 teilbar: 256, 128, 64, 32, 16."],
    "TNR811_3_07": ["Was kommt als nächstes? 1, 4, 13, 40, __", "Versuchen Sie es mit ×3 und dann mit +1.", ["80", "120", "121", "81"], "Regel: ×3, dann +1. 1→4, 4→13, 13→40, 40→121."],
    "TNR811_3_08": ["Was kommt als nächstes? 50, 46, 40, 32, 22, __", "Unterschiede erhöht: −4, −6, −8, −10...", ["10", "12", "14", "8"], "Die Unterschiede erhöhen sich um 2: −4, −6, −8, −10, −12. Also 22 − 12 = 10."],
    "TNR811_3_09": ["Was kommt als nächstes? 3, 9, 27, 81, __", "Jede Zahl ist ×3.", ["162", "243", "108", "100"], "Jede Zahl wird mit 3 multipliziert: 3, 9, 27, 81, 243."],
    "TNR811_3_10": ["Was kommt als nächstes? 2, 3, 5, 9, 17, __", "Die Unterschiede werden verdoppelt: +1, +2, +4, +8...", ["25", "33", "34", "31"], "Die Unterschiede werden verdoppelt: +1, +2, +4, +8, +16. Also 17 + 16 = 33."],
    "TNR811_3_11": ["Was kommt als nächstes? 1, 5, 13, 29, __", "Versuchen Sie es mit ×2 und dann mit +3.", ["57", "58", "61", "45"], "Regel: ×2, dann +3. 1→5, 5→13, 13→29, 29→61."],
    "TNR811_3_12": ["Was kommt als nächstes? 200, 195, 185, 170, 150, __", "Unterschiede erhöht: −5, −10, −15, −20...", ["130", "125", "120", "135"], "Die Unterschiede erhöhen sich um 5: −5, −10, −15, −20, −25. Also 150 − 25 = 125."],
    "TNR811_3_13": ["Was kommt als nächstes? 4, 16, 64, 256, __", "Jede Zahl ist ×4.", ["512", "1024", "768", "640"], "Jede Zahl wird mit 4 multipliziert: 4, 16, 64, 256, 1024."],
    "TNR811_3_14": ["Was kommt als nächstes? 1, 2, 6, 24, 120, __", "Multiplizieren Sie mit 2, dann 3, dann 4, dann 5 ...", ["240", "600", "720", "360"], "×2, ×3, ×4, ×5, ×6. Also 120 × 6 = 720. Diese werden Fakultäten genannt."],
    "TNR811_3_15": ["Was kommt als nächstes? 5, 8, 14, 26, 50, __", "Die Unterschiede werden verdoppelt: +3, +6, +12, +24...", ["74", "98", "76", "100"], "Die Unterschiede werden verdoppelt: +3, +6, +12, +24, +48. Also 50 + 48 = 98."],
    "TNR811_3_16": ["Was kommt als nächstes? 3, 10, 31, 94, __", "Versuchen Sie es mit ×3 und dann mit +1.", ["188", "282", "283", "281"], "Regel: ×3, dann +1. 3→10, 10→31, 31→94, 94→283."],
    "TNR811_3_17": ["Was kommt als nächstes? 80, 77, 71, 62, 50, __", "Unterschiede erhöht: −3, −6, −9, −12...", ["35", "38", "40", "42"], "Die Unterschiede erhöhen sich um 3: −3, −6, −9, −12, −15. Also 50 − 15 = 35."],
    "TNR811_3_18": ["Was kommt als nächstes? 1, 2, 4, 8, 16, 32, __", "Jede Zahl wird verdoppelt.", ["48", "60", "64", "36"], "Jede Zahl ist ×2: 1, 2, 4, 8, 16, 32, 64."],
    "TNR811_3_19": ["Was kommt als nächstes? 2, 7, 22, 67, __", "Versuchen Sie es mit ×3 und dann mit +1.", ["134", "200", "201", "202"], "Regel: ×3, dann +1. 2→7, 7→22, 22→67, 67→202."],
    "TNR811_3_20": ["Was kommt als nächstes? 1000, 990, 970, 940, 900, __", "Unterschiede erhöht: −10, −20, −30, −40...", ["860", "850", "840", "870"], "Die Unterschiede erhöhen sich um 10: −10, −20, −30, −40, −50. Also 900 − 50 = 850."],
    "TLR811_1_01": ["Alle Hunde sind Tiere. Spot ist ein Hund. Was ist Spot?", "Wenn Spot ein Hund ist und alle Hunde Tiere sind ...", ["Eine Pflanze", "Ein Tier", "Ein Vogel", "Ein Fisch"], "Alle Hunde sind Tiere. Spot ist ein Hund. Spot ist also ein Tier."],
    "TLR811_1_02": ["Alle Äpfel sind Früchte. Alle Früchte sind Nahrung. Folgt daraus, dass alle Äpfel Nahrung sind?", "Die Kette folgt: Äpfel → Obst → Lebensmittel.", ["Ja", "Nein", "Nur einige", "Wir können es nicht wissen"], "Äpfel sind Obst und Obst ist Nahrung. Alle Äpfel sind also Lebensmittel."],
    "TLR811_1_03": ["Tom ist größer als Sam. Sam ist größer als Ben. Wer ist der Größte?", "Ordne sie der Höhe nach.", ["Sam", "Ben", "Tom", "Mir geht es genauso"], "Tom > Sam > Ben. Tom ist der Größte."],
    "TLR811_1_04": ["Alle Katzen haben einen Schwanz. Whiskers ist eine Katze. Hat der Schnurrbart einen Schwanz?", "Wenn alle Katzen einen Schwanz hätten und Whiskers eine Katze wäre ...", ["Ja", "Nein", "Vielleicht", "Nur manchmal"], "Alle Katzen haben einen Schwanz. Whiskers ist eine Katze. Schnurrbart hat also einen Schwanz."],
    "TLR811_1_05": ["Ana ist älter als Ben. Ben ist älter als Cara. Wer ist der Jüngste?", "Ordnen Sie sie vom Ältesten zum Jüngsten.", ["Ana", "Ben", "Cara", "Sie sind gleich alt"], "Ana > Ben > Cara als Alter. Cara ist die Jüngste."],
    "TLR811_1_06": ["Alle Vögel haben Federn. Eine Schwalbe ist ein Vogel. Hat die Schwalbe Federn?", "Wenn alle Vögel Federn hätten ...", ["Nein", "Ja", "Nur im Winter", "Vielleicht"], "Alle Vögel haben Federn. Die Schwalbe ist ein Vogel. Es hat also Federn."],
    "TLR811_1_07": ["Rot ist größer als Blau. Blau ist größer als Grün. Welches ist das Kleinste?", "Sortieren Sie sie nach Größe.", ["Rot", "Blau", "Grün", "Sie sind gleich"], "Rot > Blau > Grün. Grün ist am kleinsten."],
    "TLR811_1_08": ["Alle Fische leben im Wasser. Ein Goldfisch ist ein Fisch. Wo lebt ein Goldfisch?", "Wenn alle Fische im Wasser leben würden ...", ["Auf dem Trockenen", "In den Bäumen", "Im Wasser", "am Himmel"], "Alle Fische leben im Wasser. Goldfische sind Fische. Es lebt also im Wasser."],
    "TLR811_1_09": ["Buch A hat mehr Seiten als Buch B. Buch B hat mehr Seiten als Buch C. Welches hat die wenigsten Seiten?", "Sortieren Sie die Bücher nach Seitenanzahl.", ["Buch A", "Buch B", "Buch C", "Sie sind gleich"], "A > B > C zu Seiten. Buch C hat die wenigsten Seiten."],
    "TLR811_1_10": ["Alle Quadrate haben 4 Seiten. Diese Form ist ein Quadrat. Wie viele Seiten hat es?", "Wenn es quadratisch ist ...", ["3", "4", "5", "6"], "Alle Quadrate haben 4 Seiten. Diese Form ist quadratisch. Es hat also 4 Seiten."],
    "TLR811_1_11": ["Pizza ist billiger als Steak. Steak ist billiger als Hummer. Welches ist das günstigste?", "Sortieren Sie sie nach Preis.", ["Steak", "Der Hummer", "Pizza", "Es kostet das Gleiche"], "Pizza < Steak < Hummer zu einem Preis. Pizza ist am günstigsten."],
    "TLR811_1_12": ["Alle Rosen sind Blumen. Alle Blumen sind Pflanzen. Ist die Rose eine Pflanze?", "Die Kette folgt: Rosen → Blumen → Pflanzen.", ["Ja", "Nein", "Vielleicht", "Nur rote Rosen"], "Rosen sind Blumen und Blumen sind Pflanzen. Die Rose ist also eine Pflanze."],
    "TLR811_1_13": ["Team A hat mehr Punkte erzielt als Team B. Team B hat mehr Punkte erzielt als Team C. Wer hat die meisten Punkte erzielt?", "Ordnen Sie die Teams nach ihrer Punktzahl.", ["Team C", "Team B", "Team A", "Gleichheit"], "A > B > C auf der Partitur. Team A erzielte die meisten Punkte."],
    "TLR811_1_14": ["Alle Münzen sind rund. Ein Penny ist eine Münze. Welche Form hat ein Penny?", "Wenn alle Münzen rund sind ...", ["Quadratisch", "Dreieck", "Rund", "Oval"], "Alle Münzen sind rund. Der Penny ist Währung. Es ist also rund."],
    "TLR811_1_15": ["Mia rennt schneller als Lily. Lily rennt schneller als Zoe. Wer ist der Langsamste?", "Sortieren Sie sie nach Geschwindigkeit.", ["Mia", "Lilie", "Zoe", "Mir geht es genauso"], "Mia > Lily > Zoe in Höchstgeschwindigkeit. Zoe ist die Langsamste."],
    "TLR811_1_16": ["Alle Dreiecke haben 3 Seiten. Diese Form hat 3 Seiten. Kann es ein Dreieck sein?", "Dreiecke haben 3 Seiten. Bedeutet das unbedingt, dass die Form ein Dreieck ist?", ["Ja, das kann sein", "Nein, niemals", "Nur wenn es groß ist", "Nur wenn es rot ist"], "Alle Dreiecke haben drei Seiten, und diese Form hat drei Seiten, es kann also ein Dreieck sein."],
    "TLR811_1_17": ["Ein Elefant ist schwerer als ein Pferd. Ein Pferd ist schwerer als ein Hund. Welches ist das einfachste?", "Sortieren Sie sie nach Gewicht.", ["Der Elefant", "Das Pferd", "Der Hund", "Ich singe das Gleiche"], "Elefant > Pferd > Hund nach Gewicht. Der Hund ist am einfachsten."],
    "TLR811_1_18": ["Alle Bleistifte können schreiben. Das ist ein Bleistift. Kann er schreiben?", "Wenn alle Bleistifte schreiben könnten ...", ["Ja", "Nein", "Nur manchmal", "Wir wissen es nicht"], "Alle Bleistifte können schreiben. Das ist Bleistift. Damit er schreiben kann."],
    "TLR811_1_19": ["Box A ist breiter als Box B. Box B ist breiter als Box C. Was ist breiter?", "Sortieren Sie die Felder nach Breite.", ["Kasten C", "Kasten B", "Kasten A", "Mir geht es genauso"], "A > B > C in der Breite. Box A ist die breiteste."],
    "TLR811_1_20": ["Alle Eissorten sind kalt. Das ist Eis. Ist es kalt?", "Wenn das ganze Eis kalt ist ...", ["Nein", "Vielleicht", "Ja", "Nur im Winter"], "Alle Eissorten sind kalt. Das ist Eis. Es ist also kalt."],
    "TLR811_2_01": ["Jede Schokolade ist süß. Diese Süßigkeit ist süß. Ist Schokolade SICHER?", "Nur weil jede Schokolade süß ist, bedeutet das, dass alles Süße Schokolade ist?", ["Ja, sicher", "Nein, nicht unbedingt", "Nur dunkle Schokolade", "Immer"], "Jede Schokolade ist süß, aber auch andere Dinge können süß sein. Es ist nicht unbedingt Schokolade."],
    "TLR811_2_02": ["Anna ist größer als Ben. Ben ist größer als Cara. Cara ist größer als Dan. Wer ist der zweithöchste?", "Ordnen Sie alle vier in der Reihenfolge ihrer Höhe an.", ["Anna", "Ben", "Cara", "Dan"], "Anna > Ben > Cara > Dan. Ben ist der zweitgrößte."],
    "TLR811_2_03": ["Alle Autos haben Räder. Dieses Fahrzeug hat Räder. Ist ein Auto SICHER?", "Nur Autos haben Räder?", ["Ja", "Nein, nicht unbedingt", "Nur wenn es rot ist", "Immer"], "Viele Fahrzeuge haben Räder (Fahrräder, Busse, Lastkraftwagen). Es ist nicht unbedingt ein Auto."],
    "TLR811_2_04": ["Rot ist größer als Blau. Blau ist größer als Grün. Grün ist größer als Gelb. Was ist das drittgrößte?", "Sortieren Sie alle vier nach Größe.", ["Rot", "Blau", "Grün", "Gelb"], "Rot > Blau > Grün > Gelb. Grün ist der drittgrößte."],
    "TLR811_2_05": ["Alle Quadrate sind Rechtecke. Diese Form ist rechteckig. Ist es SICHER quadratisch?", "Alle Quadrate sind Rechtecke, aber sind alle Rechtecke Quadrate?", ["Ja", "Nein, nicht unbedingt", "Nur wenn es klein ist", "Immer"], "Alle Quadrate sind Rechtecke, aber nicht alle Rechtecke sind Quadrate. Es ist möglicherweise nicht quadratisch."],
    "TLR811_2_06": ["Kim bekam 90 Punkte. Lee 85. Minute 95. Pat 80. Wer war Zweiter?", "Sortieren Sie von der höchsten zur niedrigsten Punktzahl.", ["Kim", "Lee", "Min", "Bett"], "Minute (95) > Kim (90) > Lee (85) > Pat (80). Kim war Zweite."],
    "TLR811_2_07": ["Alle Hunde bellen. Ein Tier bellt. Ist es hundesicher?", "Bellen nur Hunde?", ["Ja, sicher", "Nein, nicht unbedingt", "Nur große Hunde bellen", "Immer"], "Auch andere Tiere können bellen (z. B. Robben). Es ist nicht unbedingt ein Hund."],
    "TLR811_2_08": ["Buch A hat 200 Seiten. B ist 150. C ist 300. D ist 250. Welches ist das drittlängste?", "Sortieren Sie von den meisten Seiten zu den wenigsten.", ["Buch A", "Buch B", "Buch C", "Buch D"], "C (300) > D (250) > A (200) > B (150). Buch A ist das drittlängste."],
    "TLR811_2_09": ["Alle geraden Zahlen sind genau durch 2 teilbar. Die Zahl 15 ist nicht genau durch 2 teilbar. Was können wir über 15 sagen?", "Wenn es nicht durch 2 teilbar ist, kann es dann gerade sein?", ["Es ist ausgeglichen", "Es sind keine Haare", "Wir können es nicht wissen", "Es kann sogar sein"], "Alle geraden Zahlen sind durch 2 teilbar. 15 ist nicht durch 2 teilbar. 15 ist also nicht gerade."],
    "TLR811_2_10": ["Amy, Ben, Cat und Dan rennen. Amy schlägt Ben. Cat übertrifft Amy. Dan schlägt Cat. Wer gewinnt?", "Wenn Dan Cat schlägt und Cat Amy schlägt ...", ["Amy", "Ben", "Katze", "Dan"], "Dan > Katze > Amy > Ben. Dan gewinnt."],
    "TLR811_2_11": ["Alle Fahrräder haben 2 Räder. Dieses Fahrzeug hat 2 Räder. Ist das Fahrrad SICHER?", "Nur Fahrräder haben 2 Räder?", ["Ja", "Nein, nicht unbedingt", "Nur Mountainbikes", "Immer"], "Und Roller, Motorräder haben 2 Räder. Es ist nicht unbedingt ein Fahrrad."],
    "TLR811_2_12": ["Vier Freunde haben unterschiedliche Punkte: 70, 80, 90, 100. James hat mehr als 80, aber weniger als 100. Wie hoch war sein Punktestand?", "Welcher Wert liegt zwischen 80 und 100?", ["70", "80", "90", "100"], "Der einzige Wert zwischen 80 und 100 ist 90."],
    "TLR811_2_13": ["Alle Spinnen haben 8 Beine. Diese Kreatur hat 8 Beine. Ist es eine sichere Spinne?", "Nur Spinnen haben 8 Beine?", ["Ja", "Nein, nicht unbedingt", "Nur die Großen", "Immer"], "Und Skorpione haben 8 Beine. 8 Beine bedeuten nicht unbedingt eine Spinne."],
    "TLR811_2_14": ["Die Eiche ist höher als die Birke. Die Kiefer ist höher als die Eiche. Die Ulme ist kürzer als die Birke. Welcher Baum ist der höchste?", "Ordne alle vier Bäume an.", ["Die Eiche", "Die Birke", "Die Kiefer", "Die Ulme"], "Kiefer > Eiche > Birke > Ulme. Die Kiefer ist die höchste."],
    "TLR811_2_15": ["Alle Planeten kreisen um einen Stern. Die Erde umkreist einen Stern. Beweist dies, dass die Erde ein Planet ist?", "Umkreisen nur Planeten Sterne?", ["Ja, das beweist es", "Nein, das beweist es nicht", "Nur manchmal", "Immer"], "Und Kometen und Asteroiden umkreisen Sterne. Die Umlaufbahn allein beweist nicht, dass es sich um einen Planeten handelt."],
    "TLR811_2_16": ["Sam hat mehr Aufkleber als Mia. Mia hat mehr als Jo. Jo hat mehr als Lee. Wer hat die wenigsten?", "Bestellen Sie sie.", ["Sam", "Mia", "Jo", "Lee"], "Sam > Mia > Jo > Lee. Lee hat die wenigsten."],
    "TLR811_2_17": ["Wenn es regnet, ist der Boden nass. Der Boden ist nass. Regnet es SICHER?", "Könnte der Boden aus anderen Gründen nass sein?", ["Ja, sicher", "Nein, nicht unbedingt", "Nur im Sommer", "Immer"], "Jemand hätte es abspritzen können. Nasser Boden ist kein Beweis für Regen."],
    "TLR811_2_18": ["Die Katze wiegt weniger als der Hund. Der Hund weniger als die Schafe. Die Schafe weniger als die Kuh. Welches Tier wiegt am meisten?", "Nach Gewicht sortieren.", ["Die Katze", "Der Hund", "Die Schafe", "Die Kuh"], "Katze < Hund < Schaf < Kuh. Die Kuh wiegt am meisten."],
    "TLR811_2_19": ["Alle Äpfel sind Früchte. Das ist KEINE Frucht. Kann es Apfel sein?", "Wenn alle Äpfel Früchte sind und dieser keine Früchte ist ...", ["Ja", "Nein, das geht nicht", "Vielleicht", "Nur die Grünen"], "Alle Äpfel sind Früchte. Wenn es keine Frucht ist, kann es kein Apfel sein."],
    "TLR811_2_20": ["Vier Kinder sind 8, 9, 10, 11 Jahre alt. Kai ist größer als Zoe. Zoe als Leo. Löwe als Ivy. Wie alt ist Zoe?", "Kai ist der Älteste, dann Zoe, Leo, Ivy.", ["8", "9", "10", "11"], "Kai=11, Zoe=10, Leo=9, Ivy=8. Zoe ist 10 Jahre alt."],
    "TLR811_3_01": ["Wenn es regnet, nimmt Tom einen Regenschirm mit. Wenn er einen Regenschirm mitnimmt, bleibt er trocken. Es regnet. Wird Tom trocken bleiben?", "Die Kette folgt: Regen → Regenschirm → trocken.", ["Ja", "Nein", "Vielleicht", "Nur wenn es kalt ist"], "Regen → Regenschirm → trocken. Es regnet, also bleibt Tom trocken."],
    "TLR811_3_02": ["Wenn A wahr ist, dann ist B wahr. B ist NICHT wahr. Ist A wahr?", "Wenn A B immer wahr und B falsch machen würde ...", ["Ja", "Nein", "Vielleicht", "Wir können es nicht wissen"], "Wenn A wahr wäre, müsste B wahr sein. Aber B ist es nicht. Also kann A nicht wahr sein."],
    "TLR811_3_03": ["Heute ist Mittwoch. Welcher Tag war vor 3 Tagen?", "Countdown: Dienstag, Montag, Sonntag.", ["Montag", "Sonntag", "Samstag", "Dienstag"], "Mittwoch −1 = Dienstag, −2 = Montag, −3 = Sonntag."],
    "TLR811_3_04": ["Wer studiert, besteht die Prüfung. Wenn Sie die Prüfung bestehen, erhalten Sie die Belohnung. Maya hat es gelernt. Bekommt Maya ihre Belohnung?", "Die Kette folgt: Lernen → Bestehen der Prüfung → Belohnung.", ["Ja", "Nein", "Nur manchmal", "Wir können es nicht wissen"], "Lernen → Bestehen → Belohnung. Maya hat es gelernt, also bekommt sie die Belohnung."],
    "TLR811_3_05": ["Wenn Anna schwimmt, trägt sie eine Schwimmbrille. Anna trägt KEINE Brille. Schwimmt Anna?", "Wenn er beim Schwimmen immer eine Brille trägt und jetzt nicht mehr ...", ["Ja", "Nein", "Vielleicht", "Nur Montag"], "Wenn er schwamm, trug er eine Schutzbrille. Es trägt nicht, also schwimmt es nicht."],
    "TLR811_3_06": ["Heute ist der 28. März. Welches Datum liegt in 5 Tagen?", "Der März hat 31 Tage. Zählen Sie ab 28 vorwärts.", ["33. März", "1. April", "2. April", "3. April"], "Der März hat 31 Tage. 28 + 5 = 33. 33 − 31 = 2. Es ist also der 2. April."],
    "TLR811_3_07": ["Wenn Max Kuchen isst, wird er krank. Max ist NICHT verletzt. Hat Max Kuchen gegessen?", "Wenn der Kuchen ihn immer krank macht und jetzt nicht mehr...", ["Ja", "Nein", "Vielleicht", "Nur Schokoladenkuchen"], "Wenn er Kuchen essen würde, wäre ihm schlecht. Er hat keine Lust, also hat er nichts gegessen."],
    "TLR811_3_08": ["Wenn A zu B führt, B zu C, C zu D. Passiert A? Kommt D vor?", "Es folgt die Kette von A nach D.", ["Ja", "Nein", "Nur manchmal", "Wir können es nicht wissen"], "A → B → C → D. Wenn A, dann D."],
    "TLR811_3_09": ["Es ist Oktober. Wie viele Monate bis März (aufwärts gezählt)?", "Anzahl: November, Dezember, Januar, Februar, März.", ["4", "5", "6", "3"], "Nov. (1), Dez. (2), Jan. (3), Feb. (4), März (5). Es sind 5 Monate."],
    "TLR811_3_10": ["Wenn eine Form vier gleiche Seiten und vier rechte Winkel hat, ist sie quadratisch. Diese Form hat NICHT 4 gleiche Seiten. Sicher, dass es NICHT quadratisch ist?", "Kann es ein Quadrat ohne 4 gleiche Seiten sein?", ["Ja, es ist nicht quadratisch", "Nein, es könnte immer noch quadratisch sein", "Vielleicht", "Nur wenn es groß ist"], "Das Quadrat muss 4 gleiche Seiten haben. Wenn es sie nicht hat, ist es nicht quadratisch."],
    "TLR811_3_11": ["Wenn Sie die Taste drücken, schaltet sich das Licht ein. Wenn das Licht angeht, klingelt die Glocke. Du hast den Knopf gedrückt. was ist los", "Die Kette folgt: Knopf → Licht → Klingel.", ["Nichts", "Nur das Licht", "Die Glocke läutet", "Der Knopf geht kaputt"], "Taste → Licht → Klingel. Sie haben gedrückt, also klingelt die Glocke."],
    "TLR811_3_12": ["Heute ist Freitag. Welcher Tag wird in 10 Tagen sein?", "10 = 7 + 3. Eine ganze Woche plus 3 Tage.", ["Sonntag", "Montag", "Dienstag", "Mittwoch"], "10 Tage = 1 Woche + 3 Tage. Freitag + 3 = Montag."],
    "TLR811_3_13": ["Alle Schüler der Klasse A spielen Fußball. Tom spielt KEIN Fußball. Ist Tom in der A-Klasse?", "Wenn in A alle Fußball spielen und Tom nicht ...", ["Ja", "Nein", "Vielleicht", "Nur am Wochenende"], "Jeder in A spielt Fußball. Tom spielt nicht, also ist er nicht in der Klasse A."],
    "TLR811_3_14": ["Wenn es schneit, ist die Schule geschlossen. Wenn die Schule geschlossen ist, spielen die Kinder draußen. Es hat NICHT geschneit. Können wir SICHER sein, dass die Kinder NICHT draußen spielen?", "Könnte die Schule aus einem anderen Grund schließen?", ["Ja, wir sind sicher", "Nein, wir können nicht sicher sein", "Nur im Sommer", "Immer"], "Die Schule kann auch aus anderen Gründen (Ferien, Reparaturen) schließen. Die Kinder konnten trotzdem draußen spielen."],
    "TLR811_3_15": ["Heute ist der 30. November. Welches Datum liegt in 3 Tagen?", "Der November hat 30 Tage; Wie geht es nach dem 30. November weiter?", ["33. November", "1. Dezember", "2. Dezember", "3. Dezember"], "Der November hat 30 Tage. 30. November +1 = 1. Dezember, +2 = 2. Dezember, +3 = 3. Dezember"],
    "TLR811_3_16": ["X ist größer als Y. Y als Z. Z als W. W als V. Was ist größer?", "Wer steht an der Spitze der Kette?", ["V", "w", "Y", "X"], "X > Y > Z > W > V. X ist das größte."],
    "TLR811_3_17": ["Alle Fische können schwimmen. Etwas kann nicht schwimmen. Ist es Fisch?", "Wenn alle Fische schwimmen und dies nicht ...", ["Ja", "Nein", "Vielleicht", "Nur kleine Fische"], "Alle Fische schwimmen. Wenn es nicht schwimmen kann, ist es kein Fisch."],
    "TLR811_3_18": ["Heute ist Dienstag. Welcher Tag wird in 25 Tagen sein?", "25 ÷ 7 = 3 Wochen und 4 zusätzliche Tage.", ["Freitag", "Samstag", "Sonntag", "Montag"], "25 = 3 Wochen + 4 Tage. Dienstag + 4 = Samstag."],
    "TLR811_3_19": ["Wenn A wahr ist, muss B wahr sein. Wenn B wahr ist, muss C wahr sein. C ist NICHT wahr. Ist A wahr?", "Es funktioniert umgekehrt: Wenn C falsch ist, was ist dann mit B? Dann mit A?", ["Ja", "Nein", "Vielleicht", "Wir können es nicht wissen"], "Wenn A → B → C. C ist falsch, also ist B falsch, also ist A falsch."],
    "TLR811_3_20": ["Jede Katze ist haarig. Alles, was haarig ist, ist weich. Alles, was weich ist, lässt sich angenehm umarmen. Whiskers ist eine Katze. Ist es schön, Schnurrbärte zu umarmen?", "Die Kette folgt: Katze → haarig → weich → knuddelig.", ["Ja", "Nein", "Vielleicht", "Nur die Kätzchen"], "Katze → behaart → weich → schön. Whiskers ist eine Katze, daher ist es schön, sie zu umarmen."],
    "TSR811_1_01": ["Wie viele Seiten hat ein Würfel?", "Stellen Sie sich einen Würfel vor – zählen Sie die flachen Seiten.", ["4", "6", "8", "12"], "Ein Würfel hat 6 flache Seiten."],
    "TSR811_1_02": ["Wie viele Kanten hat ein Würfel?", "An einer Kante treffen zwei Flächen aufeinander. Zähle alle Kanten.", ["6", "8", "10", "12"], "Ein Würfel hat 12 Kanten."],
    "TSR811_1_03": ["Wie viele Eckpunkte (Ecken) hat ein Würfel?", "Ein Scheitelpunkt ist der Punkt, an dem sich die Kanten treffen.", ["4", "6", "8", "12"], "Ein Würfel hat 8 Eckpunkte (Ecken)."],
    "TSR811_1_04": ["Welche Form hat jede Seite eines Würfels?", "Alle Flächen des Würfels haben die gleiche Form.", ["Dreieck", "Rechteck", "Quadratisch", "Kreis"], "Jede Seite eines Würfels ist ein Quadrat."],
    "TSR811_1_05": ["Wie viele Flächen hat ein rechteckiger Kasten (Quader)?", "Denken Sie an einen Schuhkarton. Zählen Sie flache Gesichter.", ["4", "5", "6", "8"], "Ein Quader (rechteckiger Kasten) hat 6 Flächen."],
    "TSR811_1_06": ["Wie viele flache Flächen hat eine Kugel?", "Eine Kugel ist wie eine Kugel.", ["0", "1", "2", "4"], "Eine Kugel hat 0 flache Flächen. Es ist komplett abgerundet."],
    "TSR811_1_07": ["Wie viele flache Flächen hat ein Zylinder?", "Denken Sie an eine Blechdose. Welche flachen Seiten hat es?", ["0", "1", "2", "3"], "Ein Zylinder hat zwei flache Flächen (oberer Kreis und unterer Kreis)."],
    "TSR811_1_08": ["Welche 3D-Form hat trotzdem 6 quadratische Flächen?", "Alle Flächen sind identische Quadrate.", ["Quader", "Würfel", "Prisma", "Pyramide"], "Ein Würfel hat 6 identische quadratische Flächen."],
    "TSR811_1_09": ["Wie viele ebene Flächen hat ein Kegel?", "Denken Sie an eine Eistüte. Es hat eine einzelne flache Basis.", ["0", "1", "2", "3"], "Ein Kegel hat eine flache Fläche (kreisförmige Grundfläche)."],
    "TSR811_1_10": ["Wie viele Kanten hat eine dreieckige Pyramide (Tetraeder)?", "Es hat 4 dreieckige Flächen. Zählen Sie, wo sich die Dreiecke treffen.", ["4", "5", "6", "8"], "Eine dreieckige Pyramide (Tetraeder) hat 6 Kanten."],
    "TSR811_1_11": ["Welche Form sehen Sie, wenn Sie einen Würfel direkt von vorne betrachten?", "Sehen Sie sich eine Fläche des vorderen Würfels an.", ["Dreieck", "Kreis", "Quadratisch", "Rechteck"], "Wenn Sie direkt auf eine Seite eines Würfels schauen, sehen Sie ein Quadrat."],
    "TSR811_1_12": ["Wie viele Flächen hat ein dreieckiges Prisma?", "Stellen Sie sich eine Toblerone-Box vor – 2 Dreiecke und einige Rechtecke.", ["3", "4", "5", "6"], "Ein dreieckiges Prisma hat 5 Flächen: 2 Dreiecke und 3 Rechtecke."],
    "TSR811_1_13": ["Wie viele Eckpunkte hat eine dreieckige Pyramide (Tetraeder)?", "Zählen Sie die scharfen Ecken.", ["3", "4", "5", "6"], "Eine dreieckige Pyramide hat 4 Eckpunkte."],
    "TSR811_1_14": ["Welche Form hat die Basis eines Kegels?", "Die flache Basis eines Kegels ist…", ["Quadratisch", "Dreieck", "Kreis", "Oval"], "Die Basis eines Kegels ist ein Kreis."],
    "TSR811_1_15": ["Wie viele Kanten hat ein Quader?", "Ein Quader ist wie ein Würfel, aber mit rechteckigen Flächen. Zählen Sie die Kanten.", ["8", "10", "12", "14"], "Ein Quader hat, genau wie ein Würfel, 12 Kanten."],
    "TSR811_1_16": ["Wie viele Flächen hat eine Pyramide mit quadratischer Grundfläche?", "Es hat eine quadratische Grundfläche und dreieckige Seitenflächen.", ["4", "5", "6", "8"], "Eine Pyramide mit quadratischer Grundfläche hat 5 Flächen: 1 quadratische Grundfläche und 4 Dreiecke."],
    "TSR811_1_17": ["Wenn man 2 Würfel übereinander stapelt, ähnelt die kombinierte Form am ehesten einem…", "Zwei gestapelte Würfel ergeben eine höhere Form.", ["Würfel", "Kugeln", "Quader", "Zylinder"], "Zwei gestapelte Würfel bilden einen Quader (rechteckiger Kasten)."],
    "TSR811_1_18": ["Wie viele Eckpunkte hat ein Quader?", "Zählen Sie alle Ecken einer rechteckigen Box.", ["4", "6", "8", "10"], "Ein Quader hat 8 Eckpunkte, genau wie ein Würfel."],
    "TSR811_1_19": ["Wie viele gekrümmte Flächen hat eine Kugel?", "Eine Kugel ist überall vollkommen rund.", ["0", "1", "2", "4"], "Eine Kugel hat 1 gekrümmte Oberfläche."],
    "TSR811_1_20": ["Wie viele Flächen hat ein sechseckiges Prisma?", "Es hat zwei sechseckige Enden und rechteckige Seitenflächen. Das Sechseck hat 6 Seiten.", ["6", "7", "8", "10"], "Ein sechseckiges Prisma hat 8 Flächen: 2 Sechsecke + 6 Rechtecke."],
    "TSR811_2_01": ["Welche Form hat der Abschnitt, wenn man einen Würfel parallel zu einer der Seiten genau in zwei Hälften schneidet?", "Gerade schneiden, wie Brot schneiden.", ["Dreieck", "Kreis", "Quadratisch", "Rechteck"], "Cutting the cube parallel to one face gives you a square-shaped section."],
    "TSR811_2_02": ["8 kleine Würfel bilden einen 2×2×2 Würfel. Wie viele kleine Würfel sind vollständig verborgen (ohne sichtbare Flächen)?", "Bei der 2×2×2-Anordnung liegt jeder Würfel außen.", ["0", "1", "2", "4"], "Im 2×2×2-Würfel befindet sich jeder kleine Würfel an einer Ecke mit sichtbaren Flächen. Keiner ist verborgen."],
    "TSR811_2_03": ["Wie viele Kanten hat ein dreieckiges Prisma?", "3 Kanten am oberen Dreieck + 3 am unteren + 3, die sie verbinden.", ["6", "8", "9", "12"], "Ein dreieckiges Prisma hat 9 Kanten: 3 + 3 + 3."],
    "TSR811_2_04": ["Sie stellen 3 Würfel direkt hintereinander auf. Wie viele Flächen der kleinen Würfel sind verdeckt (berühren einen anderen Würfel)?", "Dort, wo sich die Würfel berühren, sind an jedem Gelenk zwei Flächen verborgen.", ["2", "3", "4", "6"], "Es gibt 2 Gelenke. Jeder verbirgt 2 Gesichter. Gesamtzahl der verdeckten Gesichter: 2 × 2 = 4."],
    "TSR811_2_05": ["Wie viele Kanten hat eine Pyramide mit quadratischer Grundfläche?", "4 Kanten an der Basis + 4 nach oben.", ["5", "6", "8", "10"], "Eine Pyramide mit quadratischer Grundfläche hat 8 Kanten: 4 an der Basis + 4 an den Seiten."],
    "TSR811_2_06": ["Welche Form hat der Abschnitt, wenn man einen Zylinder in zwei Hälften schneidet (senkrecht zur Höhe)?", "Wie ein Baumstamm schneiden, senkrecht zur Achse.", ["Quadratisch", "Rechteck", "Kreis", "Oval"], "Durch Schneiden des Zylinders senkrecht zur Höhe erhält man einen Kreis."],
    "TSR811_2_07": ["27 kleine Würfel bilden einen 3×3×3 Würfel. Bei wie vielen kleinen Würfeln ist außen mindestens eine Seite sichtbar?", "Nur der Würfel genau in der Mitte ist vollständig verborgen.", ["24", "25", "26", "27"], "Nur 1 Würfel (der in der Mitte) ist verborgen. 27 − 1 = 26 Würfel haben mindestens eine sichtbare Seite."],
    "TSR811_2_08": ["Wie viele Flächen hat ein fünfeckiges Prisma?", "2 fünfeckige Köpfe + rechteckige Flächen. Das Fünfeck hat 5 Seiten.", ["5", "6", "7", "8"], "Ein fünfeckiges Prisma hat 7 Flächen: 2 Fünfecke + 5 Rechtecke."],
    "TSR811_2_09": ["Wie viele Eckpunkte hat eine Pyramide mit quadratischer Grundfläche?", "4 Ecken an der Basis + 1 Punkt oben.", ["4", "5", "6", "8"], "Eine Pyramide mit quadratischer Grundfläche hat 5 Eckpunkte: 4 an der Basis + 1 Eckpunkt."],
    "TSR811_2_10": ["4 Würfel werden in einer 2×2-Quadrat-Einzelschicht platziert. Wie viele Gesichter sind von oben zu sehen?", "Jeder Würfel zeigt 1 aufgedeckt.", ["2", "3", "4", "8"], "Jeder der 4 Würfel zeigt 1 aufgedeckt. Insgesamt = 4 Gesichter nach oben."],
    "TSR811_2_11": ["Wie viele Flächen hat eine sechseckige Pyramide?", "1 sechseckige Basis + dreieckige Seitenflächen. Das Sechseck hat 6 Seiten.", ["6", "7", "8", "9"], "Eine sechseckige Pyramide hat 7 Flächen: 1 Sechseck + 6 Dreiecke."],
    "TSR811_2_12": ["Wenn man einen Würfel von einer Kante zur gegenüberliegenden Kante (diagonal durch die Mitte) schneidet, ist der Schnitt ein…", "Der Schnitt ist diagonal, bleibt aber flach.", ["Dreieck", "Quadratisch", "Rechteck", "Kreis"], "Wenn Sie von einer Kante zur gegenüberliegenden Kante schneiden, erhalten Sie einen rechteckigen Abschnitt."],
    "TSR811_2_13": ["Wie viele Flächen hat eine dreieckige Pyramide (Tetraeder)?", "Alle seine Flächen sind Dreiecke.", ["3", "4", "5", "6"], "Eine dreieckige Pyramide hat 4 dreieckige Flächen."],
    "TSR811_2_14": ["8 Würfel bilden einen 2×2×2 Würfel. Wie viele Flächen der kleinen Würfel sind auf der Außenseite des großen Würfels sichtbar?", "Der große Würfel hat 6 Flächen, die jeweils aus 4 kleinen Flächen bestehen.", ["16", "20", "24", "32"], "6 große Gesichter × je 4 kleine Gesichter = 24 sichtbare kleine Gesichter."],
    "TSR811_2_15": ["Wie viele Eckpunkte hat eine fünfeckige Grundpyramide?", "5 Ecken an der Basis + 1 Punkt oben.", ["5", "6", "7", "10"], "Eine fünfeckige Pyramide hat 6 Eckpunkte: 5 an der Basis + 1 Spitze."],
    "TSR811_2_16": ["Wie viele Kanten hat ein sechseckiges Prisma?", "6 nach oben + 6 nach unten + 6, die sie verbinden.", ["12", "14", "16", "18"], "Ein sechseckiges Prisma hat 18 Kanten: 6 + 6 + 6."],
    "TSR811_2_17": ["Entfernen Sie einen Eckwürfel aus einer 2×2×2-Anordnung. Wie viele kleine Würfel bleiben übrig?", "Sie haben 8 kleine Würfel und entfernen 1.", ["5", "6", "7", "4"], "8 − 1 = 7 Würfel übrig."],
    "TSR811_2_18": ["Wie viele Eckpunkte hat ein dreieckiges Prisma?", "3 Ecken an jedem Dreiecksende.", ["4", "5", "6", "8"], "Ein dreieckiges Prisma hat 6 Eckpunkte: 3 auf jedem Dreieck."],
    "TSR811_2_19": ["Wenn Sie alle Flächen eines 2×2×2-Würfels bemalen und ihn auseinanderfalten, wie viele kleine Würfel haben dann genau 3 Flächen bemalt?", "Im 2×2×2-Würfel befindet sich jeder kleine Würfel an der Ecke.", ["4", "6", "8", "0"], "Alle 8 Würfel in 2×2×2 sind Eckwürfel, also haben alle 8 genau 3 bemalte Flächen."],
    "TSR811_2_20": ["Wie viele Flächen hat ein achteckiges Prisma?", "2 achteckige Enden + rechteckige Flächen. Das Achteck hat 8 Seiten.", ["8", "10", "12", "16"], "Ein achteckiges Prisma hat 10 Flächen: 2 Achtecke + 8 Rechtecke."],
    "TSR811_3_01": ["Wie viele Quadrate entfaltet sich ein Würfel (die entfaltete Version)?", "Jede Seite des Würfels wird zu einem sich entfaltenden Quadrat.", ["4", "5", "6", "8"], "Ein Würfel hat 6 Flächen, also hat er im aufgeklappten Zustand 6 Quadrate."],
    "TSR811_3_02": ["Wie viele Würfel sind in einem 3×3×3-Würfel aus 27 kleinen Würfeln vollständig verborgen (keine Fläche sichtbar)?", "Nur der Würfel in der exakten Mitte zeigt nicht nach außen.", ["0", "1", "4", "8"], "Nur ein Würfel, der sich genau in der Mitte befindet, ist vollständig verborgen."],
    "TSR811_3_03": ["Welche 3D-Form erhält man, wenn man ein ungefaltetes Kreuz faltet (z. B. ein Plus von 6 Quadraten)?", "Die kreuzförmige Auffaltung ist eine der häufigsten und bekanntesten Formen.", ["Pyramide", "Quader", "Würfel", "Prisma"], "Ein Kreuz aus 6 Quadraten faltet sich zu einem Würfel."],
    "TSR811_3_04": ["Wie viele kleine Würfel haben in einem 3×3×3-Würfel genau 3 sichtbare Flächen?", "Eckwürfel haben 3 sichtbare Flächen. Wie viele Ecken hat ein Würfel?", ["4", "6", "8", "12"], "Ein Würfel hat 8 Ecken. Jeder Eckwürfel hat genau 3 sichtbare Flächen."],
    "TSR811_3_05": ["Wenn Sie zwei Würfel auf eine Fläche kleben, wie viele Flächen hat die neue Form insgesamt?", "Jeder Würfel hat 6 Seiten, aber 2 sind dort versteckt, wo sie aufgeklebt sind.", ["8", "10", "11", "12"], "6 + 6 = insgesamt 12 Gesichter. Subtrahiere 2 verdeckte Gesichter: 12 − 2 = 10."],
    "TSR811_3_06": ["Wie viele kleine Würfel haben in einem 3×3×3-Würfel genau 2 sichtbare Flächen?", "Würfel haben an den Kanten (nicht an den Ecken) zwei sichtbare Flächen. Wie viele Kanten hat ein Würfel?", ["6", "8", "12", "24"], "Ein Würfel hat 12 Kanten. Auf jeder Kante befindet sich 1 Würfel, der keine Ecke ist. 12 × 1 = 12 zweiseitige Würfel."],
    "TSR811_3_07": ["Wenn Sie einen Würfel mit einem einzigen geraden Schnitt zerteilen, wie viele Stücke erhalten Sie maximal?", "Ein einzelner Schnitt zerfällt in höchstens 2 Teile.", ["2", "3", "4", "6"], "Ein gerader Schnitt durch eine beliebige Form ergibt höchstens 2 Stücke."],
    "TSR811_3_08": ["Wie viele kleine Würfel haben in einem 3×3×3-Würfel genau eine sichtbare Seite?", "Würfel in der Mitte jeder Fläche haben 1 sichtbare Fläche. Ein Würfel hat 6 Seiten.", ["4", "6", "8", "12"], "Auf jeder der 6 Seiten befindet sich 1 zentraler Würfel. 6 × 1 = 6 Würfel mit genau einer Seite."],
    "TSR811_3_09": ["Aus wie vielen Formen besteht die Abwicklung einer Pyramide mit quadratischer Grundfläche?", "Zählen Sie die dreieckige Basis und Flächen.", ["4", "5", "6", "8"], "Es lässt sich in 5 Formen entfalten: 1 Quadrat (Basis) + 4 Dreiecke (Seiten)."],
    "TSR811_3_10": ["Wenn Sie 3 Würfel hintereinander (von Angesicht zu Angesicht) zusammenkleben, wie viele Flächen hat die neue Form?", "3 Würfel = insgesamt 18 Flächen. Es gibt 2 Gelenke, die jeweils 2 Gesichter verbergen.", ["12", "14", "16", "18"], "3 × 6 = 18 Gesichter. 2 Verbindungen × 2 versteckte Flächen = 4 versteckte. 18 − 4 = 14."],
    "TSR811_3_11": ["Wie viele kleine Würfel befinden sich in einem 4×4×4-Würfel (64 kleine Würfel) auf der Oberfläche?", "Gesamtzahl der Würfel abzüglich der darin enthaltenen. Der Innenraum ist 2×2×2.", ["48", "52", "56", "60"], "Innenraum = 2×2×2 = 8 Würfel. Außen = 64 − 8 = 56."],
    "TSR811_3_12": ["Wenn Sie einen 3×3×3-Würfel bemalen und ihn in kleine Würfel zerteilen, wie viele davon haben überhaupt keine Farbe?", "Nur der Würfel genau in der Mitte hat kein bemaltes Gesicht.", ["0", "1", "4", "8"], "Nur der Würfel in der Mitte berührt die Außenseite nicht und hat daher keine Farbe."],
    "TSR811_3_13": ["Wie viele Formen hat ein Netz für ein dreieckiges Prisma?", "2 dreieckige Enden + rechteckige Seiten.", ["3", "4", "5", "6"], "Das Netz hat 5 Formen: 2 Dreiecke + 3 Rechtecke."],
    "TSR811_3_14": ["Wenn Sie einen 2×2×2-Würfel bemalen und ihn in 8 kleine Würfel teilen, wie viele 3 Flächen werden dann genau bemalt?", "In 2×2×2 steht jeder Würfel an der Ecke.", ["4", "6", "8", "2"], "Alle 8 stehen an der Ecke, haben also alle genau 3 bemalte Gesichter."],
    "TSR811_3_15": ["Wenn Sie einen Würfel aus einer Ecke betrachten, wie viele Gesichter können Sie gleichzeitig sehen?", "Aus einer Ecke sieht man, wie sich dort die Gesichter treffen.", ["1", "2", "3", "4"], "Von einer Ecke des Würfels aus sieht man höchstens 3 Flächen."],
    "TSR811_3_16": ["In einem 3×3×3-Würfel beträgt die Gesamtzahl der von außen sichtbaren kleinen Flächen…?", "Der große Würfel hat 6 Flächen mit jeweils 9 kleinen Flächen.", ["36", "48", "54", "27"], "6 große Gesichter × 9 kleine Gesichter = 54 sichtbare kleine Gesichter."],
    "TSR811_3_17": ["Wenn Sie zwei Würfel nebeneinander kleben und den dritten auf einen Würfel legen (L-Form), wie viele Flächen hat die Form?", "2 geklebte Würfel = 10 Flächen. Das dritte oben verbirgt zwei weitere Gesichter.", ["12", "14", "16", "18"], "2 geklebte Würfel = 10 Flächen. Dritter Würfel: 10 + 6 − 2 = 14 Flächen."],
    "TSR811_3_18": ["Wie viele kleine Würfel werden benötigt, um einen 4×4×4 Würfel zu bauen?", "Multiplizieren Sie 4 × 4 × 4.", ["16", "32", "48", "64"], "4 × 4 × 4 = 64 kleine Würfel."],
    "TSR811_3_19": ["Wie viele kleine Würfel haben in einem 3×3×3-Würfel eine gemeinsame Fläche mit dem mittleren Würfel?", "Der zentrale Würfel wird von den oberen, unteren, linken, rechten, vorderen und hinteren Würfeln berührt.", ["4", "6", "8", "12"], "Der zentrale Würfel ist aus 6 Richtungen erreichbar: oben, unten, links, rechts, vorne, hinten."],
    "TSR811_3_20": ["Wenn Sie 6 Würfel in ein 2×3×1 flaches Rechteck kleben, wie viele Flächen hat die Form?", "6 Würfel = 36 Flächen. Zählt innere Verknüpfungen, die Gesichter verbergen.", ["18", "20", "22", "24"], "6 × 6 = 36 Gesichter. Es gibt 7 interne Fugen (4 horizontale + 3 vertikale), die jeweils 2 Flächen verbergen: 36 − 14 = 22."],
    "TMP811_1_01": ["Ein Bauer hat 25 Schafe. Alle laufen weg, außer 9. Wie viele Schafe sind noch übrig?", "„Alle außer 9“ bedeutet, dass 9 nicht ausgeführt wurde.", ["16", "9", "25", "0"], "„Alle bis auf 9 laufen“ bedeutet, dass 9 bleiben. Die Antwort ist 9."],
    "TMP811_1_02": ["3 Freunde teilen sich 12 Kekse zu gleichen Teilen. Wie viel bekommt jeder?", "Teilen Sie 12 durch 3.", ["3", "4", "5", "6"], "12 ÷ 3 = jeweils 4 Kekse."],
    "TMP811_1_03": ["Ein Geschäft verkauft Äpfel für 2 £ pro Stück. Wie viel kosten 5 Äpfel?", "Multiplizieren Sie den Stückpreis mit der Anzahl der Äpfel.", ["7 £", "8 £", "10 £", "12 £"], "5 × 2 £ = 10 £."],
    "TMP811_1_04": ["Wie viele Monate im Jahr haben 28 Tage?", "Denken Sie darüber nach: Haben nur einige Monate 28 Tage?", ["1", "6", "12", "2"], "Alle 12 Monate haben mindestens 28 Tage!"],
    "TMP811_1_05": ["Ein Buch besteht aus 6 Kapiteln mit jeweils 10 Seiten. Wie viele Seiten hat es insgesamt?", "Multiplizieren Sie die Anzahl der Kapitel mit den Seiten pro Kapitel.", ["16", "50", "60", "66"], "6 × 10 = 60 Seiten."],
    "TMP811_1_06": ["Sie haben 3 Kisten mit jeweils 4 Bällen. Wie viele Bälle hast du insgesamt?", "Multiplizieren Sie die Kästchen mit den Kugeln in jedem Kästchen.", ["7", "9", "12", "15"], "3 × 4 = 12 Bälle."],
    "TMP811_1_07": ["In einem Rennen überholen Sie den Zweitplatzierten. Wo bist du gerade?", "Wenn du den Zweitplatzierten überholst, nimmst du seinen Platz ein.", ["1. Platz", "2. Platz", "3. Platz", "4. Platz"], "Du bist auf dem 2. Platz. Du hast den zweiten bestanden, nicht den ersten."],
    "TMP811_1_08": ["Ein Bäcker backt 5 Kuchen pro Stunde. Wie viele Folterungen führt er in 4 Stunden durch?", "Multiplizieren Sie die Folterungen pro Stunde mit der Anzahl der Stunden.", ["9", "15", "20", "25"], "5 × 4 = 20 Kuchen."],
    "TMP811_1_09": ["Tom has 8 toys. An seinem Geburtstag bekommt er noch drei weitere. Wie viel hat er jetzt?", "Fügen Sie neue Spielsachen zu dem hinzu, was er bereits hatte.", ["5", "10", "11", "12"], "8 + 3 = 11 Spielzeuge."],
    "TMP811_1_10": ["Was wiegt mehr: 1 kg Federn oder 1 kg Steine?", "Schauen Sie sich das Gewicht an – beide wiegen 1 kg.", ["Federn", "Die Steine", "Ebenso", "Es kommt darauf an"], "Beide wiegen 1 kg, also gleich!"],
    "TMP811_1_11": ["Eine Spinne hat 8 Beine. Wie viele Beine haben 3 Spinnen?", "Multiplizieren Sie die Beine einer Spinne mit der Anzahl der Spinnen.", ["16", "20", "24", "28"], "3 × 8 = 24 Fuß."],
    "TMP811_1_12": ["Du hast 20 Bonbons und isst 3 pro Tag. Wie viele haben Sie nach 4 Tagen noch übrig?", "Berechnen Sie zunächst, wie viel Sie insgesamt gegessen haben.", ["5", "8", "10", "12"], "4 × 3 = 12 gegessen. 20 − 12 = 8 übrig."],
    "TMP811_1_13": ["Wie viele Seiten hat ein Kreis?", "Eine Seite ist eine gerade Kante. Hat der Kreis gerade Kanten?", ["0", "1", "2", "4"], "Ein Kreis hat 0 gerade Seiten."],
    "TMP811_1_14": ["Ein Auto hat 4 Räder. Wie viele Räder haben 5 Autos?", "Multiplizieren Sie die Räder eines Autos mit der Anzahl der Autos.", ["9", "15", "16", "20"], "5 × 4 = 20 Räder."],
    "TMP811_1_15": ["Ein Dutzend Eier entspricht 12. Wie viele Eier sind ein halbes Dutzend?", "Die Hälfte von 12 ist…", ["4", "5", "6", "8"], "Ein halbes Dutzend = 12 ÷ 2 = 6."],
    "TMP811_1_16": ["Wenn heute Ihr 9. Geburtstag ist, wie viele Geburtstage hatten Sie bisher?", "Der erste Geburtstag war, als du 1 wurdest; jetzt ist es der 9.", ["8", "9", "10", "1"], "Der 9. Geburtstag bedeutet, dass Sie 9 Mal gefeiert haben."],
    "TMP811_1_17": ["Eine Woche hat 7 Tage. Wie viele Tage haben 3 Wochen?", "Multiplizieren Sie die Wochentage mit der Anzahl der Wochen.", ["10", "14", "21", "28"], "3 × 7 = 21 Tage."],
    "TMP811_1_18": ["Sie haben 5,00 £ und geben 1,50 £ aus. Wie viel bleibt Ihnen übrig?", "Subtrahieren Sie, was Sie ausgegeben haben.", ["2,50 £", "3,00 £", "3,50 £", "4,00 £"], "5,00 £ − 1,50 £ = 3,50 £."],
    "TMP811_1_19": ["4 Freunde haben jeweils 6 Bälle. Wie viele Bälle haben sie zusammen?", "Multiplizieren Sie die Anzahl der Freunde mit den Bällen jeder Person.", ["10", "18", "20", "24"], "4 × 6 = 24 Bälle."],
    "TMP811_1_20": ["Wie viele Minuten hat eine halbe Stunde?", "Eine Stunde hat 60 Minuten.", ["20", "25", "30", "45"], "Halbe 60 Minuten = 30 Minuten."],
    "TMP811_2_01": ["Eine Schnecke legt in einer Minute 3 cm zurück. Wie weit kommt man in 10 Minuten?", "Geschwindigkeit mit Zeit multiplizieren.", ["13 cm", "30 cm", "33 cm", "300 cm"], "3 × 10 = 30 cm."],
    "TMP811_2_02": ["In einem magischen Quadrat ergibt jede Reihe 15. Die erste Reihe ist: 2, ?, 6. Was ist die fehlende Zahl?", "2 + ? + 6 = 15.", ["5", "6", "7", "8"], "2 + ? + 6 = 15, also ? = 15 − 2 − 6 = 7."],
    "TMP811_2_03": ["24 Bonbons werden gleichmäßig auf 6 Kinder aufgeteilt. Wie viel bekommt jeder?", "Teilen Sie die Bonbons entsprechend der Anzahl der Kinder auf.", ["3", "4", "5", "6"], "24 ÷ 6 = jeweils 4 Bonbons."],
    "TMP811_2_04": ["Ein Wasserhahn füllt einen Eimer in 10 Minuten. Wie viele Eimer kann er pro Stunde füllen?", "1 Stunde = 60 Minuten.", ["4", "5", "6", "10"], "60 ÷ 10 = 6 Eimer."],
    "TMP811_2_05": ["In einem magischen Quadrat (Summe 15) ist eine Reihe: 6, 5, ?. Was ist die fehlende Zahl?", "6 + 5 + ? = 15.", ["3", "4", "5", "6"], "6 + 5 + ? = 15, also ? = 15 − 6 − 5 = 4."],
    "TMP811_2_06": ["Ein Fahrrad fährt 12 km pro Stunde. Wie weit fährt es in 3 Stunden?", "Geschwindigkeit mit Zeit multiplizieren.", ["15 km", "24 km", "36 km", "48 km"], "12 × 3 = 36 km."],
    "TMP811_2_07": ["3 Freunde finden 30 £ und teilen es zu gleichen Teilen auf. Wie viel bekommt jeder?", "Teilen Sie 30 £ durch 3.", ["5 £", "10 £", "12 £", "15 £"], "30 £ ÷ 3 = jeweils 10 £."],
    "TMP811_2_08": ["Eine Fabrik stellt täglich 50 Spielzeuge her. Wie viel verdient er in 5 Tagen?", "Multiplizieren Sie die Anzahl der Spielzeuge pro Tag mit der Anzahl der Tage.", ["55", "100", "200", "250"], "50 × 5 = 250 Spielzeuge."],
    "TMP811_2_09": ["In einem magischen Quadrat (Summe 15) ist eine Reihe: 8, 3, ?. Was ist die fehlende Zahl?", "8 + 3 + ? = 15.", ["3", "4", "5", "6"], "8 + 3 + ? = 15, also ? = 15 − 8 − 3 = 4."],
    "TMP811_2_10": ["Sie kaufen 3 Produkte für jeweils 4,50 £. Wie viel zahlen Sie insgesamt?", "Multiplizieren Sie den Preis mit der Menge.", ["12,00 £", "13,50 £", "14,50 £", "15,00 £"], "3 × 4,50 £ = 13,50 £."],
    "TMP811_2_11": ["Ein Zug fährt 60 km pro Stunde. Wie weit fährt es in 2 Stunden?", "Geschwindigkeit mit Zeit multiplizieren.", ["62 km", "90 km", "100 km", "120 km"], "60 × 2 = 120 km."],
    "TMP811_2_12": ["36 Äpfel werden in 9er-Kisten verpackt. Wie viele Kisten werden benötigt?", "Teilen Sie 36 durch 9.", ["3", "4", "5", "6"], "36 ÷ 9 = 4 Kisten."],
    "TMP811_2_13": ["In einem magischen Quadrat (Summe 15) ist eine Reihe: 8, 1, ?. Was ist die fehlende Zahl?", "8 + 1 + ? = 15.", ["4", "5", "6", "7"], "8 + 1 + ? = 15, also ? = 15 − 8 − 1 = 6."],
    "TMP811_2_14": ["Sie haben 20 £. Ein Buch kostet 3,50 £. Wie viele Bücher können Sie sich leisten?", "Lassen Sie immer wieder 3,50 £ fallen, bis es nicht mehr geht.", ["4", "5", "6", "7"], "5 × 3,50 £ = 17,50 £ (genug). 6 × 3,50 £ = 21,00 £ (zu viel). Sie können 5 kaufen."],
    "TMP811_2_15": ["Ein Gartenschlauch füllt 2 Liter pro Minute. Wie viele Liter in 15 Minuten?", "Multiplizieren Sie den Fluss mit der Zeit.", ["17", "25", "30", "32"], "2 × 15 = 30 Liter."],
    "TMP811_2_16": ["5 Kinder teilen sich zu gleichen Teilen 35 Aufkleber. Wie viel bekommt jeder?", "Teilen Sie 35 durch 5.", ["5", "6", "7", "8"], "35 ÷ 5 = jeweils 7 Aufkleber."],
    "TMP811_2_17": ["In einem magischen Quadrat (Summe 15) ist eine Reihe: 4, 9, ?. Was ist die fehlende Zahl?", "4 + 9 + ? = 15.", ["1", "2", "3", "4"], "4 + 9 + ? = 15, also ? = 15 − 4 − 9 = 2."],
    "TMP811_2_18": ["Sparen Sie 5 £ pro Woche. In wie vielen Wochen sammeln Sie 40 £?", "Teilen Sie 40 £ durch 5 £.", ["6", "7", "8", "9"], "40 £ ÷ 5 £ = 8 Wochen."],
    "TMP811_2_19": ["Ein Drucker druckt 10 Seiten pro Minute. Wie lange dauert der Druck von 80 Seiten?", "Es teilt Seiten in Seiten pro Minute auf.", ["6 Minuten", "7 Minuten", "8 Minuten", "10 Minuten"], "80 ÷ 10 = 8 Minuten."],
    "TMP811_2_20": ["48 Studierende werden in 8er-Teams eingeteilt. Wie viele Teams werden gebildet?", "Teilen Sie 48 durch 8.", ["4", "5", "6", "7"], "48 ÷ 8 = 6 Teams."],
    "TMP811_3_01": ["Ein Geschäft verkauft Bleistifte für 50 Pence und Kugelschreiber für 1,20 £. Sie kaufen 3 Bleistifte und 2 Kugelschreiber. Wie viel zahlen Sie?", "Berechnen Sie jeden Teil einzeln und addieren Sie ihn dann.", ["3,50 £", "3,90 £", "4,10 £", "4,50 £"], "3 × 50 Pence = 1,50 £. 2 × 1,20 £ = 2,40 £. Gesamt: 1,50 £ + 2,40 £ = 3,90 £."],
    "TMP811_3_02": ["Eine Spinne hat 8 Beine, ein Hund hat 4. In einem Raum sind 3 Spinnen und 2 Hunde. Wie viele Fuß sind es insgesamt?", "Berechnen Sie zuerst die Beine der Spinnen, dann die der Hunde.", ["28", "30", "32", "36"], "3 × 8 = 24 Beine (Spinnen). 2 × 4 = 8 Fuß (Hunde). 24 + 8 = 32."],
    "TMP811_3_03": ["Die Uhr zeigt 15:45. Wie spät wird es in 2 Stunden und 30 Minuten sein?", "Addieren Sie zuerst die Stunden und dann die Minuten.", ["17:15", "17:45", "18:15", "18:45"], "15:45 + 2 Stunden = 17:45. 17:45 + 30 Min. = 18:15."],
    "TMP811_3_04": ["Sie haben 3 Münzen: 50p, 20p und 10p. Wie viele verschiedene Beträge kann man mit einer oder mehreren Münzen bilden?", "Listen Sie alle Kombinationen auf: eins, zwei, alle drei.", ["5", "6", "7", "8"], "Einzel: 50, 20, 10. Paare: 70, 60, 30. Alle Dreier: 80. Insgesamt 7 Beträge."],
    "TMP811_3_05": ["Ein Rezept sieht 250 g Mehl für 4 Personen vor. Wie viel Mehl braucht man für 12 Personen?", "12 ist dreimal mehr als 4.", ["500 g", "625 g", "750 g", "1000g"], "12 ÷ 4 = dreimal mehr. 250 × 3 = 750 g."],
    "TMP811_3_06": ["Ein Zug fährt um 9:15 Uhr ab und kommt um 11:45 Uhr an. Wie lang dauert die Reise?", "Zählen Sie die Stunden und Minuten.", ["2 Stunden", "2 Stunden und 15 Minuten", "2 Stunden und 30 Minuten", "3 Stunden"], "Von 9:15 bis 11:15 = 2 Stunden. Von 11:15 bis 11:45 = 30 Minuten. Gesamt: 2 Stunden und 30 Minuten."],
    "TMP811_3_07": ["Sie kaufen Produkte, die 2,50 £, 3,75 £, 1,25 £ und 4,50 £ kosten. Wie viel Geld bekommen Sie mit 20 £?", "Addieren Sie alle Preise und subtrahieren Sie dann 20 £.", ["6,00 £", "7,00 £", "8,00 £", "9,00 £"], "2,50 £ + 3,75 £ + 1,25 £ + 4,50 £ = 12,00 £. Rest: 20 £ − 12 £ = 8,00 £."],
    "TMP811_3_08": ["In einem Raum gibt es Stühle (je 4 Fuß) und Hocker (je 3 Fuß). Es gibt 5 Stühle und ein paar Hocker. Insgesamt sind es 29 Fuß. Wie viele Stühle gibt es?", "Berechnen Sie zuerst die Stuhlbeine und dann die Hocker.", ["2", "3", "4", "5"], "5 Stühle × 4 = 20 Fuß. 29 − 20 = 9 Fuß übrig. 9 ÷ 3 = 3 Stühle."],
    "TMP811_3_09": ["Es dauert 5 Minuten, einen Stamm in zwei Teile zu schneiden. Wie lange dauert es, es in 4 Stücke zu schneiden?", "Für 4 Stücke benötigt man 3 Schnitte, nicht 4.", ["10 Minuten", "15 Minuten", "20 Minuten", "25 Minuten"], "4 Stück = 3 Schnitte. 3 × 5 = 15 Minuten."],
    "TMP811_3_10": ["Ein Bus befördert 45 Fahrgäste. Für eine Klassenfahrt sind 3 Busse erforderlich. Wie viele Studierende können maximal teilnehmen?", "Multiplizieren Sie die Sitzplätze im Bus mit der Anzahl der Busse.", ["90", "120", "135", "150"], "3 × 45 = höchstens 135 Studierende."],
    "TMP811_3_11": ["Sie beginnen mit 100 £. Sie geben ein Viertel aus, dann ein Drittel des Restbetrags. Wie viel bleibt Ihnen übrig?", "Ein Viertel von 100 = 25. Dann ein Drittel von 75.", ["40 £", "45 £", "50 £", "55 £"], "Viertel von 100 £ = 25 £ ausgegeben, 75 £ übrig. Ein Drittel von 75 £ = 25 £ ausgegeben. 75 £ − 25 £ = 50 £."],
    "TMP811_3_12": ["Eine Sitzung beginnt um 14:50 Uhr und dauert 1 Stunde und 25 Minuten. Um wie viel Uhr endet es?", "Fügen Sie 1 Stunde und dann 25 Minuten hinzu.", ["15:55", "16:05 Uhr", "16:15 Uhr", "16:25 Uhr"], "14:50 + 1 Stunde = 15:50. 15:50 + 25 Min. = 16:15."],
    "TMP811_3_13": ["In einer Klasse sind doppelt so viele Mädchen wie Jungen. Es sind 12 Jungs. Wie viele Kinder gibt es insgesamt?", "Mädchen = 2 × Jungen.", ["24", "30", "36", "48"], "Mädchen = 2 × 12 = 24. Gesamt = 12 + 24 = 36 Kinder."],
    "TMP811_3_14": ["Sie möchten einen quadratischen Garten mit einer Seitenlänge von 8 m umzäunen. Der Zaun kostet 5 £ pro Meter. Wie hoch sind die Gesamtkosten?", "Ermitteln Sie zunächst den Umfang und multiplizieren Sie ihn dann mit dem Preis pro Meter.", ["120 £", "140 £", "160 £", "200 £"], "Umfang = 4 × 8 = 32 m. Kosten = 32 × 5 £ = 160 £."],
    "TMP811_3_15": ["Ein Film beginnt um 19:40 Uhr und dauert 1 Stunde und 50 Minuten. Um wie viel Uhr endet es?", "Fügen Sie 1 Stunde hinzu (Sie erhalten 20:40), dann 50 Minuten.", ["21:10", "21:20", "21:30 Uhr", "21:40"], "19:40 + 1 Stunde = 20:40. 20:40 + 50 Min. = 21:30."],
    "TMP811_3_16": ["Auf einem Hof ​​gibt es Kühe und Hühner. Zahlen: 8 Köpfe und 26 Fuß. Wie viele Kühe gibt es?", "Die Kuh hat 4 Beine, die Henne hat 2. Das können Sie durch Ausprobieren überprüfen.", ["3", "4", "5", "6"], "8 Köpfe. Wenn sie alle Hühner wären: 8 × 2 = 16 Fuß. Zusätzlich: 26 − 16 = 10. Jede Kuh fügt 2 zusätzliche Beine hinzu: 10 ÷ 2 = 5 Kühe."],
    "TMP811_3_17": ["Auf wie viele verschiedene Arten kann man mit 5-Pence-, 10-Pence- und 20-Pence-Münzen genau 25 Pence verdienen?", "Listet alle Kombinationen auf, die zusammen 25 Pence ergeben.", ["2", "3", "4", "5"], "Vier Modi: (1) 20+5, (2) 10+10+5, (3) 10+5+5+5, (4) 5+5+5+5+5."],
    "TMP811_3_18": ["Eine Laufstrecke ist 400 m lang. Ein Athlet läuft 3 Runden. Wie viele Kilometer legt es zurück?", "1 km = 1000 m.", ["0,8 km", "1,0 km", "1,2 km", "1,5 km"], "3 × 400 = 1200 m = 1,2 km."],
    "TMP811_3_19": ["Eine Schachtel enthält 24 Bonbons. Sie benötigen es für 100 Personen (eines für jeden). Wie viele Kartons müssen Sie kaufen?", "4 Kisten = 96 (nicht genug). Versuchen Sie es mit 5 Kartons.", ["4", "5", "6", "10"], "4 Kisten = 96 (nicht genug). 5 Kartons = 120 (genug). Sie müssen 5 kaufen."],
    "TMP811_3_20": ["Zwei Zahlen haben eine Summe von 50. Eine ist 14 größer als die andere. Was ist die größere Zahl?", "Markieren Sie die kleinere Zahl mit einem x. Dann ist x + (x + 14) = 50.", ["28", "30", "32", "36"], "x + (x + 14) = 50. 2x = 36. x = 18. Größer = 18 + 14 = 32."],
  }
});
